def load_recv_root():
    """从设置读取接收目录, 没有则用默认。"""
    try:
        s = json.loads(SETTINGS_FILE.read_text(encoding="utf-8"))
        p = s.get("recv_root")
        if p:
            return Path(p)
    except Exception:
        pass
    return DEFAULT_RECV_ROOT


def save_recv_root(path):
    set_setting("recv_root", str(path))


# 两端统一用 Alt+Shift+A(macOS 上 Alt 即 Option 键): 不与系统/常见应用的截图
# 快捷键冲突, 且好按。
DEFAULT_SHORTCUT = "Alt+Shift+A"


def _read_settings():
    try:
        return json.loads(SETTINGS_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}


def set_setting(key, value):
    try:
        APP_DATA.mkdir(parents=True, exist_ok=True)
        s = _read_settings()
        s[key] = value
        SETTINGS_FILE.write_text(json.dumps(s, ensure_ascii=False), encoding="utf-8")
    except Exception:
        pass


def get_setting(key, default=None):
    return _read_settings().get(key, default)


def load_shortcut():
    return get_setting("shot_shortcut", DEFAULT_SHORTCUT)


def load_shot_hide_window():
    """截图时是否隐藏(最小化)本应用窗口, 默认隐藏。"""
    return bool(get_setting("shot_hide_window", True))


def load_focus_after_shot():
    """截图完成后是否将本应用窗口置顶并聚焦, 默认聚焦。"""
    return bool(get_setting("focus_after_shot", True))


def load_focus_on_recv():
    """收到其他设备消息后是否将本应用窗口置顶并聚焦, 默认不抢焦点。"""
    return bool(get_setting("focus_on_recv", False))


DEFAULT_WIN_SIZE = (1000, 660)
MIN_WIN_SIZE = (820, 540)
PRESET_WIN_SIZES = [(1000, 660), (1280, 720), (1600, 900), (1920, 1080)]


def load_window_size():
    """读取保存的主窗口尺寸 (w, h), 缺省或非法时回退默认值。"""
    s = get_setting("window_size", None)
    try:
        w, h = int(s[0]), int(s[1])
        w = max(MIN_WIN_SIZE[0], min(w, 6000))
        h = max(MIN_WIN_SIZE[1], min(h, 4000))
        return w, h
    except Exception:
        return DEFAULT_WIN_SIZE


def load_remember_window():
    """下次打开是否恢复上次的窗口大小和位置, 默认开启。"""
    return bool(get_setting("remember_window", True))


def load_close_to_tray():
    """点关闭按钮时是否最小化到托盘(而非退出), 默认开启。"""
    return bool(get_setting("close_to_tray", True))


_RUN_KEY = r"Software\Microsoft\Windows\CurrentVersion\Run"
_RUN_NAME = "BitFerry"


def _autostart_command():
    if getattr(sys, "frozen", False):       # PyInstaller 打包后
        return f'"{sys.executable}"'
    return f'"{sys.executable}" "{os.path.abspath(__file__)}"'


def is_autostart_enabled() -> bool:
    if platform.system() != "Windows":
        return False
    try:
        import winreg
        with winreg.OpenKey(winreg.HKEY_CURRENT_USER, _RUN_KEY) as k:
            val, _ = winreg.QueryValueEx(k, _RUN_NAME)
            return bool(val)
    except OSError:
        return False


def set_autostart(enabled: bool):
    if platform.system() != "Windows":
        return
    try:
        import winreg
        with winreg.OpenKey(winreg.HKEY_CURRENT_USER, _RUN_KEY, 0,
                            winreg.KEY_SET_VALUE) as k:
            if enabled:
                winreg.SetValueEx(k, _RUN_NAME, 0, winreg.REG_SZ, _autostart_command())
            else:
                try:
                    winreg.DeleteValue(k, _RUN_NAME)
                except FileNotFoundError:
                    pass
    except OSError:
        pass


