_g_accent_rgb = (91, 140, 255)   # 当前主题的 RGB，paint 方法使用
_current_theme_name = "midnight"  # 供运行时读取当前主题变量

def _theme_color(key: str) -> str:
    """返回当前主题中 key 对应的颜色字符串。"""
    return THEMES.get(_current_theme_name, THEMES["midnight"]).get(key, "#888888")

def _theme_accent(alpha: int = 255):
    from PyQt6.QtGui import QColor as _QC  # noqa: import inside function is OK here
    c = _QC(*_g_accent_rgb)
    c.setAlpha(alpha)
    return c

def _set_theme(name: str):
    global ACCENT, _g_accent_rgb, _current_theme_name
    t = THEMES.get(name, THEMES["midnight"])
    ACCENT = t["accent"]
    _current_theme_name = name
    r = int(ACCENT[1:3], 16)
    g = int(ACCENT[3:5], 16)
    b = int(ACCENT[5:7], 16)
    _g_accent_rgb = (r, g, b)

def build_style(t: dict) -> str:
    return _STYLE_TPL.format(**t)

