# ----------------------------- 工具函数 -----------------------------
def _is_vpn_ip(ip):
    """检测已知 VPN/隧道专用 IP 段，这些 IP 不应作为 LAN 通信地址。
    198.18/15 = IANA benchmark（Clash/mihomo TUN 默认）
    100.64/10 = CGNAT（Tailscale / ZeroTier）
    169.254/16 = Link-local / APIPA（Windows 无 DHCP 时的自动分配）"""
    try:
        a, b = [int(x) for x in ip.split(".")[:2]]
        if a == 198 and b in (18, 19):   return True
        if a == 100 and 64 <= b <= 127:  return True
        if a == 169 and b == 254:        return True
    except Exception:
        pass
    return False


def get_local_ip():
    """优先返回真实 LAN IP。VPN 占据默认路由时，自动回落到枚举所有网卡找第一个非 VPN IP。"""
    # 先按默认路由获取
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.connect(("8.8.8.8", 80))
        ip = s.getsockname()[0]
        s.close()
        if ip and not ip.startswith("127.") and not _is_vpn_ip(ip):
            return ip
        vpn_fallback = ip   # 记下，若找不到真实 LAN IP 再用
    except Exception:
        vpn_fallback = "127.0.0.1"
    # 默认路由是 VPN IP —— 枚举网卡找真实 LAN IP
    try:
        for info in socket.getaddrinfo(socket.gethostname(), None):
            if info[0] != socket.AF_INET:
                continue
            ip = info[4][0]
            if ip and not ip.startswith("127.") and ip != "0.0.0.0" and not _is_vpn_ip(ip):
                return ip
    except Exception:
        pass
    return vpn_fallback


def _all_machine_ips():
    """返回本机所有 IPv4 地址（含 VPN），供 Discovery 过滤自身广播用。"""
    ips = set()
    try:
        for info in socket.getaddrinfo(socket.gethostname(), None):
            if info[0] == socket.AF_INET:
                ips.add(info[4][0])
    except Exception:
        pass
    ips.add(get_local_ip())
    return ips


def get_broadcast_addrs():
    """所有真实 LAN 网卡的子网广播地址 + 用户自定义网段（跳过 VPN IP）。"""
    addrs = {"255.255.255.255"}
    for ip in _all_machine_ips():
        if ip.startswith("127.") or ip == "0.0.0.0" or _is_vpn_ip(ip):
            continue
        parts = ip.split(".")
        if len(parts) == 4:
            addrs.add(f"{parts[0]}.{parts[1]}.{parts[2]}.255")
    for subnet in get_setting("extra_subnets", []):
        subnet = subnet.strip()
        if subnet:
            addrs.add(f"{subnet}.255")
    return list(addrs)


def _try_open_win_firewall():
    """Windows: 静默尝试添加防火墙入站规则，失败则忽略(需要管理员时跳过)。"""
    if platform.system() != "Windows":
        return
    try:
        exe = sys.executable
        for proto, port in [("UDP", DISCOVERY_PORT), ("TCP", TRANSFER_PORT)]:
            name = f"BitFerry-{proto}-{port}"
            subprocess.run(
                ["netsh", "advfirewall", "firewall", "add", "rule",
                 f"name={name}", "dir=in", "action=allow",
                 f"protocol={proto}", f"localport={port}",
                 f"program={exe}", "enable=yes"],
                capture_output=True, timeout=5,
                creationflags=subprocess.CREATE_NO_WINDOW)
    except Exception:
        pass


def get_hostname():
    custom = get_setting("device_name", "")
    return custom if custom else socket.gethostname()


def safe_folder_name(name):
    bad = '<>:"/\\|?*'
    return "".join("_" if c in bad else c for c in name).strip() or "Unknown"


def safe_relpath(rel):
    """把发送方提供的相对路径净化为安全子路径：剔除 .. / 绝对路径 / 盘符 / 非法字符，
    防止目录穿越写到接收根目录之外。无法净化出有效路径时返回 None。"""
    if not rel:
        return None
    parts = []
    for seg in str(rel).replace("\\", "/").split("/"):
        seg = "".join("_" if c in '<>:"|?*' else c for c in seg.strip())
        if seg in ("", ".", ".."):
            continue
        parts.append(seg)
    return "/".join(parts) or None


def recv_exact(sock, n):
    buf = bytearray()
    while len(buf) < n:
        chunk = sock.recv(min(CHUNK, n - len(buf)))
        if not chunk:
            raise ConnectionError("连接中断")
        buf.extend(chunk)
    return bytes(buf)


def human_size(n):
    for unit in ("B", "KB", "MB", "GB"):
        if n < 1024:
            return f"{n:.0f} {unit}" if unit == "B" else f"{n:.1f} {unit}"
        n /= 1024
    return f"{n:.1f} TB"


def _human_speed(bps: float) -> str:
    if bps < 1024:
        return f"{bps:.0f} B/s"
    elif bps < 1024 * 1024:
        return f"{bps / 1024:.1f} KB/s"
    else:
        return f"{bps / 1024 / 1024:.1f} MB/s"


def now_hm():
    return datetime.now().strftime("%H:%M")


# ----------------------------- macOS 屏幕录制权限 -----------------------------
def _macos_has_screen_permission() -> bool:
    """检查 macOS 是否已授权屏幕录制权限（macOS 10.15+）。"""
    try:
        import ctypes
        cg = ctypes.CDLL(
            "/System/Library/Frameworks/CoreGraphics.framework/CoreGraphics")
        cg.CGPreflightScreenCaptureAccess.restype = ctypes.c_bool
        return bool(cg.CGPreflightScreenCaptureAccess())
    except Exception:
        return True  # 无法检查时假设已有权限


def _macos_request_screen_permission():
    """向 macOS 请求屏幕录制权限（触发 TCC 弹窗，每个 bundle 只需一次）。"""
    try:
        import ctypes
        cg = ctypes.CDLL(
            "/System/Library/Frameworks/CoreGraphics.framework/CoreGraphics")
        cg.CGRequestScreenCaptureAccess()
    except Exception:
        pass


def _macos_raise_overlay(widget):
    """macOS: 把截图遮罩提到菜单栏/Dock 之上并激活。

    无边框 Tool 窗口在 macOS 是 NSPanel(可成为 key window, 故 Esc/文字输入可用),
    但默认层级低于菜单栏。这里把它提到屏保层级并加入所有 Space, 实现全屏覆盖。
    """
    try:
        import objc
        from AppKit import (NSApplication, NSScreenSaverWindowLevel,
                            NSWindowCollectionBehaviorCanJoinAllSpaces,
                            NSWindowCollectionBehaviorFullScreenAuxiliary)
        NSApplication.sharedApplication().activateIgnoringOtherApps_(True)
        view = objc.objc_object(c_void_p=int(widget.winId()))
        win = view.window()
        if win is not None:
            win.setLevel_(NSScreenSaverWindowLevel)
            win.setCollectionBehavior_(
                int(NSWindowCollectionBehaviorCanJoinAllSpaces)
                | int(NSWindowCollectionBehaviorFullScreenAuxiliary))
            win.makeKeyAndOrderFront_(None)
    except Exception:
        pass


# ----------------------------- 主动截图(系统级) -----------------------------
def take_screenshot(get_clipboard_image=None):
    """
    区域截图。
    - macOS: screencapture -i 交互式区域选择, 直接出图。
    - Windows: 调用系统截图工具(新版 ms-screenclip / 旧版 snippingtool /clip)做区域选择,
               结果在剪贴板, 通过 get_clipboard_image 回调取出。
    get_clipboard_image: 可选回调, 返回 QImage 或 None (从 Qt 剪贴板读图, 需在主线程预备好)。
    返回截图文件路径, 取消或失败返回 None。
    """
    tmp = Path(tempfile.gettempdir()) / f"lantong_shot_{int(time.time())}.png"
    system = platform.system()
    try:
        if system == "Darwin":
            # -i 交互式区域截图(用户拖选区域); 取消则不生成文件
            subprocess.run(["screencapture", "-i", str(tmp)], check=True)
            if tmp.exists() and tmp.stat().st_size > 0:
                return str(tmp)
            return None

        if system == "Windows":
            return _windows_region_screenshot(tmp, get_clipboard_image)

        # Linux 等: 尝试区域工具, 退回全屏
        for cmd in (["gnome-screenshot", "-a", "-f", str(tmp)],
                    ["spectacle", "-r", "-b", "-n", "-o", str(tmp)],
                    ["scrot", "-s", str(tmp)]):
            try:
                subprocess.run(cmd, check=True)
                if tmp.exists() and tmp.stat().st_size > 0:
                    return str(tmp)
            except Exception:
                continue
        try:
            import mss
            with mss.mss() as sct:
                sct.shot(output=str(tmp))
            return str(tmp)
        except Exception:
            from PIL import ImageGrab
            ImageGrab.grab().save(str(tmp))
            return str(tmp)
    except Exception as e:
        print("截图失败:", e)
        return None


def _windows_region_screenshot(tmp, get_clipboard_image):
    """Windows 区域截图: 启动系统截图工具 -> 用户选区 -> 从剪贴板取图。"""
    # 记录调用前剪贴板序列号(用于判断用户是否真的截了新图)
    import ctypes
    try:
        user32 = ctypes.windll.user32
        before_seq = user32.GetClipboardSequenceNumber()
    except Exception:
        before_seq = None

    launched = False
    # 新版 Windows 10/11: ms-screenclip 协议直接进入区域截图模式
    for cmd in (
        ["explorer.exe", "ms-screenclip:"],
        ["snippingtool.exe", "/clip"],
    ):
        try:
            subprocess.Popen(cmd, creationflags=subprocess.CREATE_NO_WINDOW)
            launched = True
            break
        except Exception:
            continue
    if not launched:
        # 都失败则退回全屏
        try:
            import mss
            with mss.mss() as sct:
                sct.shot(output=str(tmp))
            return str(tmp)
        except Exception:
            return None

    # 轮询剪贴板, 等待用户完成选区(最多约 60 秒)
    import ctypes
    deadline = time.time() + 60
    while time.time() < deadline:
        time.sleep(0.4)
        try:
            seq = ctypes.windll.user32.GetClipboardSequenceNumber()
        except Exception:
            seq = None
        if before_seq is not None and seq is not None and seq == before_seq:
            continue  # 剪贴板还没变, 用户还在截或没开始
        # 剪贴板变了 -> 尝试取图
        img = get_clipboard_image() if get_clipboard_image else None
        if img is not None:
            try:
                img.save(str(tmp), "PNG")
                if tmp.exists() and tmp.stat().st_size > 0:
                    return str(tmp)
            except Exception:
                pass
        # 剪贴板变了但不是图片(可能用户复制了别的), 继续等一会儿
    return None


# ----------------------------- 应用内区域截图(自绘) -----------------------------
def _grab_virtual_desktop():
    """抓取整个虚拟桌面(支持多显示器)为一张 QPixmap。

    返回 (pixmap, 逻辑几何 QRect)。pixmap 带 devicePixelRatio, 内含设备像素。
    """
    screens = QGuiApplication.screens()
    vrect = QRect()
    for s in screens:
        vrect = vrect.united(s.geometry())
    dpr = QGuiApplication.primaryScreen().devicePixelRatio() or 1.0
    canvas = QPixmap(int(round(vrect.width() * dpr)), int(round(vrect.height() * dpr)))
    canvas.setDevicePixelRatio(dpr)
    canvas.fill(QColor(0, 0, 0))
    p = QPainter(canvas)
    for s in screens:
        pm = s.grabWindow(0)
        g = s.geometry()
        p.drawPixmap(QPoint(g.x() - vrect.x(), g.y() - vrect.y()), pm)
    p.end()
    return canvas, vrect


class _Annotation:
    """一个标注对象。坐标都用 overlay 的逻辑坐标。"""
    def __init__(self, kind, color, width):
        self.kind = kind            # 'rect' | 'ellipse' | 'arrow' | 'pen' | 'text'
        self.color = color
        self.width = width
        self.p1 = QPoint()
        self.p2 = QPoint()
        self.points = []            # pen 自由曲线
        self.text = ""              # text
        self.font = None            # text


def _arrow_polygon(a: QPoint, b: QPoint, width: float):
    """实心锥形箭头(类似 Snipaste/微信): 尾部细、向箭头处略变宽、再展开成箭头。"""
    import math
    ax, ay, bx, by = a.x(), a.y(), b.x(), b.y()
    dx, dy = bx - ax, by - ay
    L = math.hypot(dx, dy)
    if L < 2:
        return None
    ux, uy = dx / L, dy / L          # 轴向单位向量
    px, py = -uy, ux                 # 垂直单位向量
    head_len = min(L * 0.6, max(16.0, width * 3.8))
    head_half = max(7.0, width * 2.2)
    shaft_half = max(2.2, width * 0.95)
    tail_half = max(1.2, width * 0.45)
    hx, hy = bx - ux * head_len, by - uy * head_len   # 箭头根部中心
    return QPolygonF([
        QPointF(ax + px * tail_half, ay + py * tail_half),     # 尾上
        QPointF(hx + px * shaft_half, hy + py * shaft_half),   # 杆上(箭根)
        QPointF(hx + px * head_half, hy + py * head_half),     # 箭翼上
        QPointF(bx, by),                                       # 箭尖
        QPointF(hx - px * head_half, hy - py * head_half),     # 箭翼下
        QPointF(hx - px * shaft_half, hy - py * shaft_half),   # 杆下
        QPointF(ax - px * tail_half, ay - py * tail_half),     # 尾下
    ])


def _draw_annotation(p: QPainter, ann: "_Annotation"):
    """把一个标注绘制到给定 painter(逻辑坐标系)。"""
    pen = QPen(ann.color, ann.width)
    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
    pen.setJoinStyle(Qt.PenJoinStyle.RoundJoin)
    p.setPen(pen)
    p.setBrush(Qt.BrushStyle.NoBrush)
    if ann.kind == "rect":
        p.drawRect(QRect(ann.p1, ann.p2).normalized())
    elif ann.kind == "ellipse":
        p.drawEllipse(QRect(ann.p1, ann.p2).normalized())
    elif ann.kind == "pen":
        if len(ann.points) >= 2:
            path = QPainterPath()
            path.moveTo(QPointF(ann.points[0]))
            for pt in ann.points[1:]:
                path.lineTo(QPointF(pt))
            p.drawPath(path)
    elif ann.kind == "arrow":
        poly = _arrow_polygon(ann.p1, ann.p2, ann.width)
        if poly is not None:
            p.setPen(Qt.PenStyle.NoPen)
            p.setBrush(ann.color)
            p.drawPolygon(poly)
    elif ann.kind == "text":
        if ann.text:
            f = ann.font or p.font()
            p.setFont(f)
            p.setPen(ann.color)
            fm = QFontMetrics(f)
            p.drawText(QPoint(ann.p1.x() + 3, ann.p1.y() + fm.ascent() + 3), ann.text)


def _pt_seg_dist(p: QPoint, a: QPoint, b: QPoint) -> float:
    import math
    ax, ay, bx, by, pxx, pyy = a.x(), a.y(), b.x(), b.y(), p.x(), p.y()
    dx, dy = bx - ax, by - ay
    if dx == 0 and dy == 0:
        return math.hypot(pxx - ax, pyy - ay)
    t = ((pxx - ax) * dx + (pyy - ay) * dy) / (dx * dx + dy * dy)
    t = max(0.0, min(1.0, t))
    return math.hypot(pxx - (ax + t * dx), pyy - (ay + t * dy))


def _ann_bounds(ann: "_Annotation") -> QRect:
    if ann.kind == "pen":
        if not ann.points:
            return QRect()
        xs = [pt.x() for pt in ann.points]
        ys = [pt.y() for pt in ann.points]
        return QRect(QPoint(min(xs), min(ys)), QPoint(max(xs), max(ys)))
    if ann.kind == "text":
        fm = QFontMetrics(ann.font or QFont())
        w = fm.horizontalAdvance(ann.text) + 6
        h = fm.height() + 6
        return QRect(ann.p1, QSize(w, h))
    return QRect(ann.p1, ann.p2).normalized()


def _ann_hit(ann: "_Annotation", pos: QPoint) -> bool:
    tol = max(8, ann.width + 5)
    if ann.kind in ("rect", "ellipse"):
        r = QRect(ann.p1, ann.p2).normalized()
        outer = r.adjusted(-tol, -tol, tol, tol)
        inner = r.adjusted(tol, tol, -tol, -tol)
        if not outer.contains(pos):
            return False
        if inner.width() > 0 and inner.height() > 0 and inner.contains(pos):
            return False
        return True
    if ann.kind == "arrow":
        return _pt_seg_dist(pos, ann.p1, ann.p2) <= max(tol, ann.width * 2)
    if ann.kind == "pen":
        return any(_pt_seg_dist(pos, ann.points[i], ann.points[i + 1]) <= tol
                   for i in range(len(ann.points) - 1))
    if ann.kind == "text":
        return _ann_bounds(ann).contains(pos)
    return False


def _ann_translate(ann: "_Annotation", dx: int, dy: int):
    ann.p1 = QPoint(ann.p1.x() + dx, ann.p1.y() + dy)
    ann.p2 = QPoint(ann.p2.x() + dx, ann.p2.y() + dy)
    if ann.points:
        ann.points = [QPoint(pt.x() + dx, pt.y() + dy) for pt in ann.points]


def _tool_icon(kind: str, color: str = "#E6E8EC", size: int = 18) -> QIcon:
    """为工具条按钮画一个清晰的小图标。"""
    pm = QPixmap(size, size)
    pm.fill(Qt.GlobalColor.transparent)
    p = QPainter(pm)
    p.setRenderHint(QPainter.RenderHint.Antialiasing)
    pen = QPen(QColor(color), 1.8)
    pen.setCapStyle(Qt.PenCapStyle.RoundCap)
    pen.setJoinStyle(Qt.PenJoinStyle.RoundJoin)
    p.setPen(pen)
    p.setBrush(Qt.BrushStyle.NoBrush)
    m = 3
    if kind == "rect":
        p.drawRect(m, m + 1, size - 2 * m, size - 2 * m - 2)
    elif kind == "ellipse":
        p.drawEllipse(m, m, size - 2 * m, size - 2 * m)
    elif kind == "arrow":
        a = QPoint(m + 1, size - m - 1)
        b = QPoint(size - m, m + 1)
        p.drawLine(a, b)
        p.drawLine(b, QPoint(b.x() - 6, b.y()))
        p.drawLine(b, QPoint(b.x(), b.y() + 6))
    elif kind == "pen":
        path = QPainterPath()
        path.moveTo(m, size - m - 1)
        path.cubicTo(m + 3, m, size - m - 3, size - m, size - m, m + 1)
        p.drawPath(path)
    elif kind == "text":
        f = QFont()
        f.setPixelSize(int(size * 0.72))
        f.setBold(True)
        p.setFont(f)
        p.drawText(pm.rect(), Qt.AlignmentFlag.AlignCenter, "T")
    p.end()
    return QIcon(pm)


_HANDLE_KEYS = ("tl", "t", "tr", "r", "br", "b", "bl", "l")
_HANDLE_CURSORS = {
    "tl": Qt.CursorShape.SizeFDiagCursor, "br": Qt.CursorShape.SizeFDiagCursor,
    "tr": Qt.CursorShape.SizeBDiagCursor, "bl": Qt.CursorShape.SizeBDiagCursor,
    "t": Qt.CursorShape.SizeVerCursor, "b": Qt.CursorShape.SizeVerCursor,
    "l": Qt.CursorShape.SizeHorCursor, "r": Qt.CursorShape.SizeHorCursor,
}


def _handle_points(r: QRect) -> dict:
    cx, cy = r.center().x(), r.center().y()
    return {
        "tl": r.topLeft(), "t": QPoint(cx, r.top()), "tr": r.topRight(),
        "r": QPoint(r.right(), cy), "br": r.bottomRight(),
        "b": QPoint(cx, r.bottom()), "bl": r.bottomLeft(), "l": QPoint(r.left(), cy),
    }


def _handle_at(r: QRect, pos: QPoint, tol: int = 7):
    for k, pt in _handle_points(r).items():
        if abs(pos.x() - pt.x()) <= tol and abs(pos.y() - pt.y()) <= tol:
            return k
    return None


def _resize_rect(r: QRect, handle: str, pt: QPoint) -> QRect:
    l, t, rr, b = r.left(), r.top(), r.right(), r.bottom()
    if "l" in handle:
        l = pt.x()
    if "r" in handle:
        rr = pt.x()
    if "t" in handle:
        t = pt.y()
    if "b" in handle:
        b = pt.y()
    return QRect(QPoint(l, t), QPoint(rr, b)).normalized()


def _enum_window_rects_macos(vrect: QRect):
    """macOS 上枚举可见的普通应用窗口(按 Z 序, 最上层在前), 转成 overlay 本地逻辑坐标。

    用 CGWindowListCopyWindowInfo: 返回的 bounds 已是逻辑点(左上原点), 与 Qt 逻辑
    坐标一致, 直接减去 vrect 原点即可, 无需 dpr 换算。只取 layer==0 的普通窗口,
    自动排除菜单栏 / Dock / 控制中心等系统层, 以及我们自己的进程。失败返回空表。
    """
    rects = []
    try:
        import os
        import Quartz
        our_pid = os.getpid()
        opts = (Quartz.kCGWindowListOptionOnScreenOnly |
                Quartz.kCGWindowListExcludeDesktopElements)
        wins = Quartz.CGWindowListCopyWindowInfo(opts, Quartz.kCGNullWindowID)
        if not wins:
            return []
        for w in wins:                      # 已按前→后 Z 序
            try:
                if int(w.get(Quartz.kCGWindowLayer, 0)) != 0:
                    continue                 # 只要普通应用窗口层, 排除菜单栏/Dock 等
                if int(w.get(Quartz.kCGWindowOwnerPID, 0)) == our_pid:
                    continue                 # 排除自己
                alpha = w.get(Quartz.kCGWindowAlpha, 1.0)
                if alpha is not None and float(alpha) <= 0.0:
                    continue                 # 全透明窗口(占位/覆盖层)忽略
                b = w.get(Quartz.kCGWindowBounds)
                if not b:
                    continue
                x = float(b.get("X", 0.0))
                y = float(b.get("Y", 0.0))
                ww = float(b.get("Width", 0.0))
                hh = float(b.get("Height", 0.0))
                if ww < 12 or hh < 12:
                    continue
                rects.append(QRect(int(round(x - vrect.x())), int(round(y - vrect.y())),
                                   int(round(ww)), int(round(hh))))
            except Exception:
                continue
    except Exception:
        return []
    return rects


def _enum_window_rects(vrect: QRect, dpr: float):
    """枚举当前可见的顶层窗口(按 Z 序, 最上层在前), 转成 overlay 本地逻辑坐标。

    用于"截图时高亮鼠标所在窗口"。Windows / macOS 均已实现, 其他平台返回空表。
    """
    sysname = platform.system()
    if sysname == "Darwin":
        return _enum_window_rects_macos(vrect)
    rects = []
    if sysname != "Windows":
        return rects
    try:
        import os
        import ctypes
        from ctypes import wintypes
        user32 = ctypes.windll.user32
        dwmapi = ctypes.windll.dwmapi
        user32.GetWindowRect.argtypes = [wintypes.HWND, ctypes.POINTER(wintypes.RECT)]
        dwmapi.DwmGetWindowAttribute.argtypes = [
            wintypes.HWND, wintypes.DWORD, ctypes.c_void_p, wintypes.DWORD]
        user32.GetWindowThreadProcessId.argtypes = [
            wintypes.HWND, ctypes.POINTER(wintypes.DWORD)]
        our_pid = os.getpid()
        DWMWA_EXTENDED_FRAME_BOUNDS = 9
        DWMWA_CLOAKED = 14
        EnumProc = ctypes.WINFUNCTYPE(ctypes.c_bool, wintypes.HWND, wintypes.LPARAM)

        def cb(hwnd, lparam):
            try:
                if not user32.IsWindowVisible(hwnd) or user32.IsIconic(hwnd):
                    return True
                pid = wintypes.DWORD()
                user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
                if pid.value == our_pid:
                    return True
                cloaked = wintypes.DWORD(0)
                dwmapi.DwmGetWindowAttribute(hwnd, DWMWA_CLOAKED,
                                             ctypes.byref(cloaked), ctypes.sizeof(cloaked))
                if cloaked.value != 0:
                    return True
                r = wintypes.RECT()
                if dwmapi.DwmGetWindowAttribute(
                        hwnd, DWMWA_EXTENDED_FRAME_BOUNDS,
                        ctypes.byref(r), ctypes.sizeof(r)) != 0:
                    user32.GetWindowRect(hwnd, ctypes.byref(r))
                w, h = r.right - r.left, r.bottom - r.top
                if w < 12 or h < 12:
                    return True
                lx = r.left / dpr - vrect.x()
                ly = r.top / dpr - vrect.y()
                rects.append(QRect(int(round(lx)), int(round(ly)),
                                   int(round(w / dpr)), int(round(h / dpr))))
            except Exception:
                pass
            return True

        user32.EnumWindows(EnumProc(cb), 0)
    except Exception:
        return []
    return rects


def _vk_for_key(k: str):
    k = k.strip()
    if len(k) == 1:
        c = k.upper()
        if "A" <= c <= "Z" or "0" <= c <= "9":
            return ord(c)
    ku = k.upper()
    if ku.startswith("F") and ku[1:].isdigit():
        n = int(ku[1:])
        if 1 <= n <= 24:
            return 0x70 + (n - 1)
    specials = {
        "SPACE": 0x20, "ENTER": 0x0D, "RETURN": 0x0D, "TAB": 0x09,
        "INSERT": 0x2D, "DELETE": 0x2E, "HOME": 0x24, "END": 0x23,
        "PGUP": 0x21, "PAGEUP": 0x21, "PGDOWN": 0x22, "PAGEDOWN": 0x22,
        "PRINT": 0x2C, "PRTSC": 0x2C,
    }
    return specials.get(ku)


def _parse_win_hotkey(seq_str: str):
    """把 'Ctrl+Shift+A' 解析为 (Win32 修饰位, 虚拟键码)。失败返回 (0, None)。"""
    MOD_ALT, MOD_CONTROL, MOD_SHIFT, MOD_WIN = 0x0001, 0x0002, 0x0004, 0x0008
    mods, vk = 0, None
    for p in [s.strip() for s in seq_str.split("+") if s.strip()]:
        pl = p.lower()
        if pl in ("ctrl", "control"):
            mods |= MOD_CONTROL
        elif pl == "shift":
            mods |= MOD_SHIFT
        elif pl == "alt":
            mods |= MOD_ALT
        elif pl in ("meta", "win", "cmd", "super"):
            mods |= MOD_WIN
        else:
            vk = _vk_for_key(p)
    return mods, vk


class _GlobalHotkey(QAbstractNativeEventFilter):
    """Windows 全局热键: 不聚焦 BitFerry 也能触发截图。"""
    WM_HOTKEY = 0x0312
    HOTKEY_ID = 0xB17F

    def __init__(self, callback):
        super().__init__()
        self._callback = callback
        self._registered = False
        self._hwnd = 0
        import ctypes
        self._user32 = ctypes.windll.user32

    def register(self, hwnd, seq_str) -> bool:
        self.unregister()
        mods, vk = _parse_win_hotkey(seq_str)
        if vk is None:
            return False
        MOD_NOREPEAT = 0x4000
        self._hwnd = int(hwnd)
        ok = bool(self._user32.RegisterHotKey(self._hwnd, self.HOTKEY_ID,
                                              mods | MOD_NOREPEAT, vk))
        self._registered = ok
        return ok

    def unregister(self):
        if self._registered:
            try:
                self._user32.UnregisterHotKey(self._hwnd, self.HOTKEY_ID)
            except Exception:
                pass
            self._registered = False

    def nativeEventFilter(self, eventType, message):
        try:
            et = bytes(eventType) if not isinstance(eventType, (bytes, bytearray)) else eventType
            if et == b"windows_generic_MSG":
                from ctypes import wintypes
                msg = wintypes.MSG.from_address(int(message))
                if msg.message == self.WM_HOTKEY and msg.wParam == self.HOTKEY_ID:
                    self._callback()
                    return True, 0
        except Exception:
            pass
        return False, 0


def _parse_mac_shortcut(seq_str):
    """'Alt+Shift+A' -> (修饰键标志位, 主键字符小写)。"""
    SHIFT, CTRL, OPT, CMD = 0x20000, 0x40000, 0x80000, 0x100000
    mods, key = 0, ""
    for tok in (seq_str or "").replace(" ", "").split("+"):
        t = tok.lower()
        if t == "shift":
            mods |= SHIFT
        elif t in ("ctrl", "control"):
            mods |= CTRL
        elif t in ("alt", "option", "opt"):
            mods |= OPT
        elif t in ("cmd", "command", "meta"):
            mods |= CMD
        elif tok:
            key = tok.lower()
    return mods, key


class _MacGlobalHotkey:
    """macOS 全局热键: 不聚焦 BitFerry 也能触发截图。
    用 NSEvent 全局监听(需"辅助功能"权限)。仅在 App 未聚焦时触发,
    聚焦时由应用内 QShortcut 处理, 两者互不重复。"""
    MOD_MASK = 0x20000 | 0x40000 | 0x80000 | 0x100000  # shift/ctrl/option/command

    def __init__(self, callback):
        self._callback = callback
        self._monitor = None

    def register(self, seq_str) -> bool:
        self.unregister()
        mods, key = _parse_mac_shortcut(seq_str)
        if not key:
            return False
        try:
            from AppKit import NSEvent
            NSEventMaskKeyDown = 1 << 10

            def handler(event):
                try:
                    if (int(event.modifierFlags()) & self.MOD_MASK) == mods and \
                       (event.charactersIgnoringModifiers() or "").lower() == key:
                        self._callback()
                except Exception:
                    pass
            self._monitor = NSEvent.addGlobalMonitorForEventsMatchingMask_handler_(
                NSEventMaskKeyDown, handler)
            return self._monitor is not None
        except Exception:
            return False

    def unregister(self):
        if self._monitor is not None:
            try:
                from AppKit import NSEvent
                NSEvent.removeMonitor_(self._monitor)
            except Exception:
                pass
            self._monitor = None


class _TextInput(QLineEdit):
    committed = pyqtSignal(str)
    cancelled = pyqtSignal()

    def keyPressEvent(self, e):
        if e.key() == Qt.Key.Key_Escape:
            self.cancelled.emit()
            return
        if e.key() in (Qt.Key.Key_Return, Qt.Key.Key_Enter):
            self.committed.emit(self.text())
            return
        super().keyPressEvent(e)

    def focusOutEvent(self, e):
        super().focusOutEvent(e)
        self.committed.emit(self.text())


class ScreenshotOverlay(QWidget):
    """应用内区域截图: 暗化遮罩 + 拖拽选区 + 标注工具(矩形/椭圆/箭头/画笔/文字)。

    交互类似微信: 先拖拽选区, 松手后弹出工具条, 选工具在选区上标注,
    点 ✓ / 回车 / 双击完成, Esc / 右键 / ✕ 取消。
    全程在本进程内完成, 关闭后焦点自然回到本应用, 因此能可靠地置顶聚焦。
    on_done(path|None) 在完成(给出 PNG 路径)或取消(None)时回调。
    """

    COLORS = ["#FB3B4E", "#FFC400", "#2ECC71", "#3B82F6", "#FFFFFF", "#000000"]
    WIDTHS = [("细", 2), ("中", 4), ("粗", 7)]

    def __init__(self, full_pixmap, vrect, on_done, win_rects=None):
        super().__init__()
        self._full = full_pixmap
        self._vrect = vrect
        self._on_done = on_done
        self._done_called = False
        # 选区
        self._origin = None
        self._cur = None
        self._dragging = False
        self._sel = QRect()
        self._mode = "selecting"          # 'selecting' -> 'annotating'
        # 鼠标悬停窗口高亮(类似微信: 移到哪个窗口就高亮哪个, 单击即选中)
        self._win_rects = win_rects or []
        self._hover_win = None
        # 选区框的缩放/移动
        self._sel_resizing = None         # handle key
        self._sel_moving = False
        self._sel_orig = QRect()
        self._drag_start = None
        # 标注
        self._annotations = []
        self._cur_ann = None
        self._drawing = False
        self._selected = None             # 选中的标注索引
        self._moving = False
        self._move_last = None
        self._ann_resizing = None         # (idx, handle)
        self._tool = None                 # None 表示未选工具(此时不画)
        self._color = QColor(self.COLORS[0])
        self._width = 4
        self._toolbar = None
        self._text_edit = None
        self.setWindowFlags(
            Qt.WindowType.FramelessWindowHint
            | Qt.WindowType.WindowStaysOnTopHint
            | Qt.WindowType.Tool)
        self.setCursor(Qt.CursorShape.CrossCursor)
        self.setGeometry(vrect)
        self.setMouseTracking(True)
        self.setFocusPolicy(Qt.FocusPolicy.StrongFocus)

    def showEvent(self, e):
        super().showEvent(e)
        self.setFocus()
        # 打开时立即根据鼠标位置高亮所在窗口, 实现"默认截取指针所在应用框"
        self._hover_win = self._win_at(self.mapFromGlobal(QCursor.pos()))
        self.update()

    def _win_at(self, pos: QPoint):
        for r in self._win_rects:                 # 已按 Z 序(最上层在前)
            if r.contains(pos):
                return r.intersected(self.rect())
        return None

    # ---------- 选区/绘制 ----------
    def _drag_rect(self) -> QRect:
        if self._origin is None or self._cur is None:
            return QRect()
        return QRect(self._origin, self._cur).normalized()

    def _is_manual_drag(self) -> bool:
        return (self._dragging and self._origin is not None and self._cur is not None
                and (self._cur - self._origin).manhattanLength() >= 6)

    def _active_sel(self) -> QRect:
        if self._mode == "selecting":
            if self._is_manual_drag():
                return self._drag_rect()
            return self._hover_win or QRect()
        return self._sel

    def _clamp_to_sel(self, pt: QPoint) -> QPoint:
        r = self._sel
        x = min(max(pt.x(), r.left()), r.right())
        y = min(max(pt.y(), r.top()), r.bottom())
        return QPoint(x, y)

    def paintEvent(self, e):
        p = QPainter(self)
        p.drawPixmap(0, 0, self._full)
        p.fillRect(self.rect(), QColor(0, 0, 0, 120))
        sel = self._active_sel()
        if sel.width() > 0 and sel.height() > 0:
            dpr = self._full.devicePixelRatio()
            src = QRectF(sel.x() * dpr, sel.y() * dpr,
                         sel.width() * dpr, sel.height() * dpr)
            p.drawPixmap(QRectF(sel), self._full, src)   # 选区高亮还原
            # 标注(裁剪在选区内)
            if self._mode == "annotating":
                p.save()
                p.setRenderHint(QPainter.RenderHint.Antialiasing)
                p.setClipRect(sel)
                for ann in self._annotations:
                    _draw_annotation(p, ann)
                if self._cur_ann is not None:
                    _draw_annotation(p, self._cur_ann)
                p.restore()
            # 选区边框 + 尺寸
            p.setPen(QPen(QColor("#5B8CFF"), 2))
            p.setBrush(Qt.BrushStyle.NoBrush)
            p.drawRect(sel)
            label = f"{sel.width()} × {sel.height()}"
            p.setPen(QColor("#FFFFFF"))
            ty = sel.y() - 8 if sel.y() > 24 else sel.y() + 18
            p.drawText(sel.x() + 2, ty, label)
            # 选区 8 个缩放手柄(仅标注阶段)
            if self._mode == "annotating":
                for pt in _handle_points(sel).values():
                    self._draw_handle(p, pt)
                # 选中标注: 画手柄(矩形/椭圆 8 点, 箭头 2 端点) 或虚线框
                if self._selected is not None and 0 <= self._selected < len(self._annotations):
                    self._draw_ann_selection(p, self._annotations[self._selected])
        else:
            p.setPen(QColor(255, 255, 255, 200))
            p.drawText(self.rect(), Qt.AlignmentFlag.AlignCenter,
                       "拖动选择截图区域，或单击高亮的窗口，Esc / 右键取消")
        p.end()

    def _draw_handle(self, p, pt):
        s = 4
        p.setPen(QPen(QColor("#5B8CFF"), 1))
        p.setBrush(QColor("#FFFFFF"))
        p.drawRect(QRect(pt.x() - s, pt.y() - s, 2 * s, 2 * s))

    def _draw_ann_selection(self, p, ann):
        if ann.kind in ("rect", "ellipse"):
            r = QRect(ann.p1, ann.p2).normalized()
            for pt in _handle_points(r).values():
                self._draw_handle(p, pt)
        elif ann.kind == "arrow":
            self._draw_handle(p, ann.p1)
            self._draw_handle(p, ann.p2)
        else:
            br = _ann_bounds(ann).adjusted(-4, -4, 4, 4)
            p.setPen(QPen(QColor("#FFFFFF"), 1, Qt.PenStyle.DashLine))
            p.setBrush(Qt.BrushStyle.NoBrush)
            p.drawRect(br)

    # ---------- 鼠标 ----------
    def mousePressEvent(self, e):
        if e.button() == Qt.MouseButton.RightButton:
            self._finish(None)
            return
        if e.button() != Qt.MouseButton.LeftButton:
            return
        if self._mode == "selecting":
            self._origin = e.pos()
            self._cur = e.pos()
            self._dragging = True
            self.update()
            return
        # ---- annotating ----
        if self._text_edit is not None:
            return
        pos = e.pos()
        # 1) 选区缩放手柄
        h = _handle_at(self._sel, pos)
        if h:
            self._sel_resizing = h
            self._sel_orig = QRect(self._sel)
            return
        # 2) 选中标注的缩放手柄(矩形/椭圆/箭头)
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            ah = self._ann_handle_at(self._annotations[self._selected], pos)
            if ah:
                self._ann_resizing = (self._selected, ah)
                return
        # 3) 命中已有标注 -> 选中并可拖动
        hit = self._hit_test(pos)
        if hit is not None:
            self._selected = hit
            self._moving = True
            self._move_last = pos
            self.update()
            return
        # 4) 没选工具且在选区边框上 -> 移动整个选区
        if not self._tool and self._on_sel_border(pos):
            self._selected = None
            self._sel_moving = True
            self._move_last = pos
            self.update()
            return
        # 5) 空白处: 取消选中; 有工具则开始画新标注
        self._selected = None
        if not self._tool or not self._sel.contains(pos):
            self.update()
            return
        if self._tool == "text":
            self._begin_text(pos)
            return
        ann = _Annotation(self._tool, QColor(self._color), self._width)
        ann.p1 = pos
        ann.p2 = pos
        if self._tool == "pen":
            ann.points = [pos]
        self._cur_ann = ann
        self._drawing = True
        self.update()

    def _hit_test(self, pos):
        for i in range(len(self._annotations) - 1, -1, -1):
            if _ann_hit(self._annotations[i], pos):
                return i
        return None

    def _ann_handle_at(self, ann, pos):
        if ann.kind in ("rect", "ellipse"):
            return _handle_at(QRect(ann.p1, ann.p2).normalized(), pos)
        if ann.kind == "arrow":
            tol = 7
            if (pos - ann.p1).manhattanLength() <= tol * 2:
                return "a1"
            if (pos - ann.p2).manhattanLength() <= tol * 2:
                return "a2"
        return None

    def _on_sel_border(self, pos, tol=6) -> bool:
        r = self._sel
        outer = r.adjusted(-tol, -tol, tol, tol)
        inner = r.adjusted(tol, tol, -tol, -tol)
        if not outer.contains(pos):
            return False
        return not (inner.width() > 0 and inner.height() > 0 and inner.contains(pos))

    def mouseMoveEvent(self, e):
        pos = e.pos()
        if self._mode == "selecting":
            if self._dragging:
                self._cur = pos
            else:
                self._hover_win = self._win_at(pos)
            self.update()
            return
        # ---- annotating ----
        if self._sel_resizing:
            new = _resize_rect(self._sel_orig, self._sel_resizing, pos)
            new = new.intersected(self.rect())
            if new.width() >= 8 and new.height() >= 8:
                self._sel = new
                self._position_toolbar()
            self.update()
            return
        if self._sel_moving and self._move_last is not None:
            dx, dy = pos.x() - self._move_last.x(), pos.y() - self._move_last.y()
            self._move_last = pos
            self._sel.translate(dx, dy)
            self._position_toolbar()
            self.update()
            return
        if self._ann_resizing is not None:
            idx, h = self._ann_resizing
            ann = self._annotations[idx]
            pt = self._clamp_to_sel(pos)
            if ann.kind == "arrow":
                if h == "a1":
                    ann.p1 = pt
                else:
                    ann.p2 = pt
            else:
                new = _resize_rect(QRect(ann.p1, ann.p2).normalized(), h, pt)
                ann.p1, ann.p2 = new.topLeft(), new.bottomRight()
            self.update()
            return
        if self._moving and self._selected is not None and self._move_last is not None:
            dx, dy = pos.x() - self._move_last.x(), pos.y() - self._move_last.y()
            self._move_last = pos
            _ann_translate(self._annotations[self._selected], dx, dy)
            self.update()
            return
        if self._drawing and self._cur_ann is not None:
            pt = self._clamp_to_sel(pos)
            self._cur_ann.p2 = pt
            if self._cur_ann.kind == "pen":
                self._cur_ann.points.append(pt)
            self.update()
            return
        # 无拖动: 根据悬停位置更新光标
        self._update_hover_cursor(pos)

    def _update_hover_cursor(self, pos):
        h = _handle_at(self._sel, pos)
        if h:
            self.setCursor(_HANDLE_CURSORS[h])
            return
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            ah = self._ann_handle_at(self._annotations[self._selected], pos)
            if ah in _HANDLE_CURSORS:
                self.setCursor(_HANDLE_CURSORS[ah])
                return
            if ah:
                self.setCursor(Qt.CursorShape.SizeAllCursor)
                return
        if self._hit_test(pos) is not None:
            self.setCursor(Qt.CursorShape.SizeAllCursor)
            return
        if not self._tool and self._on_sel_border(pos):
            self.setCursor(Qt.CursorShape.SizeAllCursor)
            return
        if self._tool and self._sel.contains(pos):
            self.setCursor(Qt.CursorShape.CrossCursor)
            return
        self.setCursor(Qt.CursorShape.ArrowCursor)

    def mouseReleaseEvent(self, e):
        if e.button() != Qt.MouseButton.LeftButton:
            return
        if self._mode == "selecting" and self._dragging:
            self._cur = e.pos()
            # 注意: 要在把 _dragging 置 False 之前判断是否为手动拖拽
            moved = (self._cur - self._origin).manhattanLength() >= 6
            self._dragging = False
            if moved:                   # 手动拖出的区域优先
                sel = self._drag_rect()
            else:                       # 轻点 -> 选中悬停的窗口
                sel = self._hover_win or QRect()
            if sel.width() < 5 or sel.height() < 5:
                self._finish(None)
                return
            self._sel = sel.intersected(self.rect())
            self._mode = "annotating"
            self.setCursor(Qt.CursorShape.ArrowCursor)
            self._build_toolbar()
            self.update()
            return
        if self._sel_resizing:
            self._sel_resizing = None
            return
        if self._sel_moving:
            self._sel_moving = False
            return
        if self._ann_resizing is not None:
            self._ann_resizing = None
            return
        if self._moving:
            self._moving = False
            return
        if self._drawing and self._cur_ann is not None:
            self._drawing = False
            ann = self._cur_ann
            self._cur_ann = None
            if self._ann_is_valid(ann):
                self._annotations.append(ann)
            self.update()

    def mouseDoubleClickEvent(self, e):
        if self._mode == "annotating" and self._sel.contains(e.pos()) \
                and self._text_edit is None and self._hit_test(e.pos()) is None \
                and _handle_at(self._sel, e.pos()) is None:
            self._confirm()

    def _ann_is_valid(self, ann):
        if ann.kind == "pen":
            return len(ann.points) >= 2
        d = (ann.p2 - ann.p1).manhattanLength()
        return d >= 3

    # ---------- 文字标注 ----------
    def _begin_text(self, pos):
        ed = _TextInput(self)
        f = QFont()
        f.setPointSize(14)
        ed.setFont(f)
        ed.setStyleSheet(
            f"background:transparent; border:1px dashed {self._color.name()};"
            f" color:{self._color.name()}; padding:1px;")
        ed.move(pos)
        ed.resize(200, ed.sizeHint().height())
        ed.committed.connect(lambda t, e=ed, pt=pos, c=QColor(self._color), fo=QFont(f):
                             self._commit_text(t, e, pt, c, fo))
        ed.cancelled.connect(lambda e=ed: self._cancel_text(e))
        ed.show()
        ed.setFocus()
        self._text_edit = ed

    def _commit_text(self, text, ed, pos, color, font):
        if self._text_edit is None:
            return
        self._text_edit = None
        if text.strip():
            ann = _Annotation("text", color, self._width)
            ann.p1 = pos
            ann.text = text
            ann.font = font
            self._annotations.append(ann)
        ed.deleteLater()
        self.update()

    def _cancel_text(self, ed):
        self._text_edit = None
        ed.deleteLater()
        self.update()

    # ---------- 键盘 ----------
    def keyPressEvent(self, e):
        if e.key() == Qt.Key.Key_Escape:
            self._finish(None)
        elif e.key() in (Qt.Key.Key_Backspace, Qt.Key.Key_Delete):
            self._delete_selected()
        elif e.key() in (Qt.Key.Key_Return, Qt.Key.Key_Enter):
            if self._mode == "annotating":
                self._confirm()
        elif e.key() == Qt.Key.Key_Z and (e.modifiers() & Qt.KeyboardModifier.ControlModifier):
            self._undo()
        else:
            super().keyPressEvent(e)

    def _delete_selected(self):
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            self._annotations.pop(self._selected)
            self._selected = None
            self.update()

    def _undo(self):
        if self._annotations:
            self._annotations.pop()
            self._selected = None
            self.update()

    # ---------- 工具条 ----------
    def _build_toolbar(self):
        if self._toolbar is not None:
            return
        bar = QFrame(self)
        bar.setObjectName("shotToolbar")
        bar.setStyleSheet(
            "#shotToolbar { background:#23262E; border:1px solid #3A3F4B; border-radius:8px; }"
            " QToolButton { background:transparent; color:#E6E8EC; border:none;"
            " border-radius:6px; padding:5px 7px; font-size:15px; }"
            " QToolButton:hover { background:#343945; }"
            " QToolButton:checked { background:#5B8CFF; color:#FFFFFF; }")
        lay = QHBoxLayout(bar)
        lay.setContentsMargins(6, 4, 6, 4)
        lay.setSpacing(2)
        self._tool_btns = {}

        def add_tool(key, tip):
            b = QToolButton(bar)
            b.setIcon(_tool_icon(key))
            b.setIconSize(QSize(18, 18))
            b.setToolTip(tip)
            b.setCheckable(True)
            b.setCursor(Qt.CursorShape.PointingHandCursor)
            b.clicked.connect(lambda _=False, k=key: self._select_tool(k))
            lay.addWidget(b)
            self._tool_btns[key] = b

        add_tool("rect", "矩形")
        add_tool("ellipse", "椭圆")
        add_tool("arrow", "箭头")
        add_tool("pen", "画笔")
        add_tool("text", "文字")

        self._add_sep(lay)
        # 颜色
        self._color_btns = []
        for c in self.COLORS:
            b = QToolButton(bar)
            b.setCheckable(True)
            b.setCursor(Qt.CursorShape.PointingHandCursor)
            b.setFixedSize(20, 20)
            b.setStyleSheet(
                f"QToolButton {{ background:{c}; border:1px solid #555; border-radius:10px; }}"
                f" QToolButton:checked {{ border:2px solid #5B8CFF; }}")
            b.clicked.connect(lambda _=False, col=c: self._select_color(col))
            if c == self._color.name(QColor.NameFormat.HexRgb).upper() or \
               QColor(c).name() == self._color.name():
                b.setChecked(True)
            lay.addWidget(b)
            self._color_btns.append((c, b))
        if not any(b.isChecked() for _, b in self._color_btns):
            self._color_btns[0][1].setChecked(True)

        self._add_sep(lay)
        # 线宽
        self._width_btns = []
        for label, w in self.WIDTHS:
            b = QToolButton(bar)
            b.setText(label)
            b.setCheckable(True)
            b.setCursor(Qt.CursorShape.PointingHandCursor)
            b.clicked.connect(lambda _=False, ww=w: self._select_width(ww))
            if w == self._width:
                b.setChecked(True)
            lay.addWidget(b)
            self._width_btns.append((w, b))

        self._add_sep(lay)
        b_undo = QToolButton(bar); b_undo.setText("↶"); b_undo.setToolTip("撤销 (Ctrl+Z)")
        b_undo.setCursor(Qt.CursorShape.PointingHandCursor)
        b_undo.clicked.connect(self._undo); lay.addWidget(b_undo)
        b_cancel = QToolButton(bar); b_cancel.setText("✕"); b_cancel.setToolTip("取消 (Esc)")
        b_cancel.setCursor(Qt.CursorShape.PointingHandCursor)
        b_cancel.setStyleSheet("QToolButton { color:#FF6B6B; }")
        b_cancel.clicked.connect(lambda: self._finish(None)); lay.addWidget(b_cancel)
        b_ok = QToolButton(bar); b_ok.setText("✓"); b_ok.setToolTip("完成 (回车/双击)")
        b_ok.setCursor(Qt.CursorShape.PointingHandCursor)
        b_ok.setStyleSheet("QToolButton { color:#2ECC71; font-weight:bold; }")
        b_ok.clicked.connect(self._confirm); lay.addWidget(b_ok)

        bar.adjustSize()
        self._toolbar = bar
        self._position_toolbar()
        bar.show()
        bar.raise_()

    def _add_sep(self, lay):
        sep = QFrame()
        sep.setFixedWidth(1)
        sep.setStyleSheet("background:#3A3F4B;")
        lay.addWidget(sep)

    def _position_toolbar(self):
        bar = self._toolbar
        if bar is None:
            return
        bw, bh = bar.width(), bar.height()
        sel = self._sel
        x = sel.left()
        y = sel.bottom() + 8
        if y + bh > self.height():
            y = sel.top() - bh - 8
        if y < 0:
            y = sel.top() + 8
        x = min(max(0, x), max(0, self.width() - bw))
        bar.move(x, y)

    def _select_tool(self, key):
        self._tool = key
        self._selected = None             # 选工具即取消选中, 进入绘制
        for k, b in self._tool_btns.items():
            b.setChecked(k == key)
        self.setCursor(Qt.CursorShape.CrossCursor if key else Qt.CursorShape.ArrowCursor)
        self.update()

    def _select_color(self, c):
        self._color = QColor(c)
        for cc, b in self._color_btns:
            b.setChecked(cc == c)
        # 若当前有选中的标注, 同时改它的颜色
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            self._annotations[self._selected].color = QColor(c)
            self.update()

    def _select_width(self, w):
        self._width = w
        for ww, b in self._width_btns:
            b.setChecked(ww == w)
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            self._annotations[self._selected].width = w
            self.update()

    # ---------- 完成/取消 ----------
    def _confirm(self):
        self._finish(self._crop_and_save())

    def _crop_and_save(self):
        try:
            sel = self._sel
            dpr = self._full.devicePixelRatio()
            phys = QRect(int(sel.x() * dpr), int(sel.y() * dpr),
                         int(sel.width() * dpr), int(sel.height() * dpr))
            result = self._full.copy(phys)
            result.setDevicePixelRatio(dpr)        # 让 painter 工作在逻辑坐标
            if self._annotations:
                pr = QPainter(result)
                pr.setRenderHint(QPainter.RenderHint.Antialiasing)
                pr.translate(-sel.x(), -sel.y())   # overlay 逻辑坐标 -> 裁剪图坐标
                pr.setClipRect(sel)
                for ann in self._annotations:
                    _draw_annotation(pr, ann)
                pr.end()
            result.setDevicePixelRatio(1.0)        # 保存为全分辨率
            IMG_DIR.mkdir(parents=True, exist_ok=True)
            out = IMG_DIR / f"stage_{int(time.time() * 1000)}.png"
            result.save(str(out), "PNG")
            return str(out)
        except Exception:
            return None

    def _finish(self, path):
        if self._done_called:
            return
        self._done_called = True
        cb = self._on_done
        self.close()
        # 等 overlay 彻底关闭后再回调, 确保焦点能干净地回到主窗口。
        QTimer.singleShot(0, lambda: cb(path))


class _EditorCanvas(QWidget):
    """图片编辑画布: 在一张已有图片上做标注(矩形/椭圆/箭头/画笔/文字)、裁剪、旋转。

    标注坐标统一存放在"图片像素坐标"中; 画布按 self._scale 缩放显示, 鼠标坐标在
    进入逻辑前转换为图片坐标。裁剪/旋转会把当前标注烘焙进底图后清空, 几何变换只作
    用于底图。被 ImageEditorDialog 承载。
    """

    def __init__(self, pixmap):
        super().__init__()
        self._pixmap = pixmap                 # 全分辨率工作底图
        self._scale = 1.0
        self.on_changed = None                # 画布尺寸变化回调(供 dialog 调整)
        # 标注
        self._annotations = []
        self._cur_ann = None
        self._drawing = False
        self._selected = None
        self._moving = False
        self._move_last = None
        self._ann_resizing = None
        self._tool = None
        self._color = QColor(ScreenshotOverlay.COLORS[0])
        self._width = 4
        self._text_edit = None
        # 裁剪
        self._crop_mode = False
        self._crop_rect = QRect()
        self._crop_resizing = None
        self._crop_orig = QRect()
        self._crop_moving = False
        self._crop_drawing = False
        self.setMouseTracking(True)
        self.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
        self._recompute_scale()

    # ---------- 坐标/缩放 ----------
    def _recompute_scale(self):
        screen = QApplication.primaryScreen()
        avail = screen.availableGeometry() if screen else QRect(0, 0, 1200, 800)
        max_w = max(320, int(avail.width() * 0.78))
        max_h = max(240, int(avail.height() * 0.68))
        iw, ih = self._pixmap.width(), self._pixmap.height()
        s = 1.0
        if iw and ih:
            s = min(1.0, max_w / iw, max_h / ih)
        self._scale = s if s > 0 else 1.0
        self.setFixedSize(max(1, int(iw * self._scale)), max(1, int(ih * self._scale)))
        if callable(self.on_changed):
            self.on_changed()
        self.update()

    def _to_img(self, pos):
        return QPoint(int(round(pos.x() / self._scale)), int(round(pos.y() / self._scale)))

    def _to_widget(self, pt):
        return QPoint(int(round(pt.x() * self._scale)), int(round(pt.y() * self._scale)))

    def _img_rect(self):
        return QRect(0, 0, self._pixmap.width(), self._pixmap.height())

    def _clamp(self, pt):
        r = self._img_rect()
        return QPoint(min(max(pt.x(), 0), r.right()), min(max(pt.y(), 0), r.bottom()))

    # ---------- 绘制 ----------
    def paintEvent(self, e):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        p.save()
        p.scale(self._scale, self._scale)
        p.drawPixmap(0, 0, self._pixmap)
        for ann in self._annotations:
            _draw_annotation(p, ann)
        if self._cur_ann is not None:
            _draw_annotation(p, self._cur_ann)
        p.restore()
        if self._crop_mode and self._crop_rect.width() > 0 and self._crop_rect.height() > 0:
            wr = QRect(self._to_widget(self._crop_rect.topLeft()),
                       self._to_widget(self._crop_rect.bottomRight()))
            outside = QPainterPath()
            outside.addRect(QRectF(self.rect()))
            inner = QPainterPath()
            inner.addRect(QRectF(wr))
            p.fillPath(outside.subtracted(inner), QColor(0, 0, 0, 120))
            p.setPen(QPen(QColor("#5B8CFF"), 2))
            p.setBrush(Qt.BrushStyle.NoBrush)
            p.drawRect(wr)
            for pt in _handle_points(wr).values():
                self._draw_handle(p, pt)
        elif self._selected is not None and 0 <= self._selected < len(self._annotations):
            self._draw_ann_selection(p, self._annotations[self._selected])
        p.end()

    def _draw_handle(self, p, pt):
        s = 4
        p.setPen(QPen(QColor("#5B8CFF"), 1))
        p.setBrush(QColor("#FFFFFF"))
        p.drawRect(QRect(pt.x() - s, pt.y() - s, 2 * s, 2 * s))

    def _draw_ann_selection(self, p, ann):
        if ann.kind in ("rect", "ellipse"):
            r = QRect(ann.p1, ann.p2).normalized()
            wr = QRect(self._to_widget(r.topLeft()), self._to_widget(r.bottomRight()))
            for pt in _handle_points(wr).values():
                self._draw_handle(p, pt)
        elif ann.kind == "arrow":
            self._draw_handle(p, self._to_widget(ann.p1))
            self._draw_handle(p, self._to_widget(ann.p2))
        else:
            br = _ann_bounds(ann).adjusted(-4, -4, 4, 4)
            wr = QRect(self._to_widget(br.topLeft()), self._to_widget(br.bottomRight()))
            p.setPen(QPen(QColor("#FFFFFF"), 1, Qt.PenStyle.DashLine))
            p.setBrush(Qt.BrushStyle.NoBrush)
            p.drawRect(wr)

    # ---------- 工具状态(供 dialog 调用) ----------
    def set_tool(self, key):
        self._tool = key
        self._selected = None
        self.setCursor(Qt.CursorShape.CrossCursor if key else Qt.CursorShape.ArrowCursor)
        self.update()

    def set_color(self, c):
        self._color = QColor(c)
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            self._annotations[self._selected].color = QColor(c)
            self.update()

    def set_width(self, w):
        self._width = w
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            self._annotations[self._selected].width = w
            self.update()

    def undo(self):
        if self._annotations:
            self._annotations.pop()
            self._selected = None
            self.update()

    def delete_selected(self):
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            self._annotations.pop(self._selected)
            self._selected = None
            self.update()

    # ---------- 裁剪/旋转 ----------
    def toggle_crop(self):
        if self._crop_mode:
            self.apply_crop()
        else:
            self._crop_mode = True
            self._set_tool_silent(None)
            self._selected = None
            r = self._img_rect()
            m = max(0, min(r.width(), r.height()) // 12)
            self._crop_rect = r.adjusted(m, m, -m, -m)
            self.setCursor(Qt.CursorShape.ArrowCursor)
            self.update()

    def _set_tool_silent(self, key):
        self._tool = key

    def cancel_crop(self):
        self._crop_mode = False
        self._crop_rect = QRect()
        self._crop_drawing = self._crop_moving = False
        self._crop_resizing = None
        self.update()

    def apply_crop(self):
        if not self._crop_mode:
            return
        r = self._crop_rect.normalized().intersected(self._img_rect())
        self._crop_mode = False
        self._crop_rect = QRect()
        if r.width() < 5 or r.height() < 5:
            self.update()
            return
        self._bake()
        self._pixmap = self._pixmap.copy(r)
        self._annotations.clear()
        self._selected = None
        self._recompute_scale()

    def rotate(self, cw=True):
        if self._crop_mode:
            self.cancel_crop()
        self._bake()
        t = QTransform()
        t.rotate(90 if cw else -90)
        self._pixmap = self._pixmap.transformed(
            t, Qt.TransformationMode.SmoothTransformation)
        self._annotations.clear()
        self._selected = None
        self._recompute_scale()

    def _bake(self):
        if not self._annotations:
            return
        p = QPainter(self._pixmap)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        for ann in self._annotations:
            _draw_annotation(p, ann)
        p.end()

    def result_pixmap(self):
        if self._crop_mode:
            self.apply_crop()
        self._bake()
        self._annotations.clear()
        return self._pixmap

    # ---------- 命中测试 ----------
    def _hit_test(self, pos):
        for i in range(len(self._annotations) - 1, -1, -1):
            if _ann_hit(self._annotations[i], pos):
                return i
        return None

    def _ann_handle_at(self, ann, pos):
        tol = max(6, int(round(8 / self._scale)))
        if ann.kind in ("rect", "ellipse"):
            return _handle_at(QRect(ann.p1, ann.p2).normalized(), pos, tol)
        if ann.kind == "arrow":
            if (pos - ann.p1).manhattanLength() <= tol * 2:
                return "a1"
            if (pos - ann.p2).manhattanLength() <= tol * 2:
                return "a2"
        return None

    # ---------- 鼠标 ----------
    def mousePressEvent(self, e):
        if e.button() != Qt.MouseButton.LeftButton:
            return
        pos_w = e.pos()
        pos = self._to_img(pos_w)
        tol = max(6, int(round(8 / self._scale)))
        if self._crop_mode:
            h = _handle_at(self._crop_rect.normalized(), pos, tol)
            if h:
                self._crop_resizing = h
                self._crop_orig = QRect(self._crop_rect.normalized())
                return
            if self._crop_rect.normalized().contains(pos):
                self._crop_moving = True
                self._move_last = pos
                return
            self._crop_rect = QRect(pos, pos)
            self._crop_drawing = True
            self._move_last = pos
            return
        if self._text_edit is not None:
            return
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            ah = self._ann_handle_at(self._annotations[self._selected], pos)
            if ah:
                self._ann_resizing = (self._selected, ah)
                return
        hit = self._hit_test(pos)
        if hit is not None:
            self._selected = hit
            self._moving = True
            self._move_last = pos
            self.update()
            return
        self._selected = None
        if not self._tool:
            self.update()
            return
        if self._tool == "text":
            self._begin_text(pos, pos_w)
            return
        ann = _Annotation(self._tool, QColor(self._color), self._width)
        ann.p1 = self._clamp(pos)
        ann.p2 = ann.p1
        if self._tool == "pen":
            ann.points = [ann.p1]
        self._cur_ann = ann
        self._drawing = True
        self.update()

    def mouseMoveEvent(self, e):
        pos = self._to_img(e.pos())
        if self._crop_mode:
            if self._crop_resizing:
                self._crop_rect = _resize_rect(
                    self._crop_orig, self._crop_resizing, self._clamp(pos))
                self.update()
                return
            if self._crop_drawing:
                self._crop_rect = QRect(self._move_last, self._clamp(pos)).normalized()
                self.update()
                return
            if self._crop_moving and self._move_last is not None:
                dx, dy = pos.x() - self._move_last.x(), pos.y() - self._move_last.y()
                self._move_last = pos
                r = self._crop_rect.translated(dx, dy)
                ir = self._img_rect()
                if r.left() < 0:
                    r.translate(-r.left(), 0)
                if r.top() < 0:
                    r.translate(0, -r.top())
                if r.right() > ir.right():
                    r.translate(ir.right() - r.right(), 0)
                if r.bottom() > ir.bottom():
                    r.translate(0, ir.bottom() - r.bottom())
                self._crop_rect = r
                self.update()
                return
            self._update_crop_cursor(pos)
            return
        if self._ann_resizing is not None:
            idx, h = self._ann_resizing
            ann = self._annotations[idx]
            pt = self._clamp(pos)
            if ann.kind == "arrow":
                if h == "a1":
                    ann.p1 = pt
                else:
                    ann.p2 = pt
            else:
                new = _resize_rect(QRect(ann.p1, ann.p2).normalized(), h, pt)
                ann.p1, ann.p2 = new.topLeft(), new.bottomRight()
            self.update()
            return
        if self._moving and self._selected is not None and self._move_last is not None:
            dx, dy = pos.x() - self._move_last.x(), pos.y() - self._move_last.y()
            self._move_last = pos
            _ann_translate(self._annotations[self._selected], dx, dy)
            self.update()
            return
        if self._drawing and self._cur_ann is not None:
            pt = self._clamp(pos)
            self._cur_ann.p2 = pt
            if self._cur_ann.kind == "pen":
                self._cur_ann.points.append(pt)
            self.update()
            return
        self._update_hover_cursor(pos)

    def _update_crop_cursor(self, pos):
        tol = max(6, int(round(8 / self._scale)))
        h = _handle_at(self._crop_rect.normalized(), pos, tol)
        if h:
            self.setCursor(_HANDLE_CURSORS[h])
        elif self._crop_rect.normalized().contains(pos):
            self.setCursor(Qt.CursorShape.SizeAllCursor)
        else:
            self.setCursor(Qt.CursorShape.CrossCursor)

    def _update_hover_cursor(self, pos):
        if self._selected is not None and 0 <= self._selected < len(self._annotations):
            ah = self._ann_handle_at(self._annotations[self._selected], pos)
            if ah in _HANDLE_CURSORS:
                self.setCursor(_HANDLE_CURSORS[ah])
                return
            if ah:
                self.setCursor(Qt.CursorShape.SizeAllCursor)
                return
        if self._hit_test(pos) is not None:
            self.setCursor(Qt.CursorShape.SizeAllCursor)
            return
        if self._tool:
            self.setCursor(Qt.CursorShape.CrossCursor)
            return
        self.setCursor(Qt.CursorShape.ArrowCursor)

    def mouseReleaseEvent(self, e):
        if e.button() != Qt.MouseButton.LeftButton:
            return
        if self._crop_mode:
            self._crop_resizing = None
            self._crop_moving = False
            self._crop_drawing = False
            return
        if self._ann_resizing is not None:
            self._ann_resizing = None
            return
        if self._moving:
            self._moving = False
            return
        if self._drawing and self._cur_ann is not None:
            self._drawing = False
            ann = self._cur_ann
            self._cur_ann = None
            if self._ann_is_valid(ann):
                self._annotations.append(ann)
            self.update()

    def _ann_is_valid(self, ann):
        if ann.kind == "pen":
            return len(ann.points) >= 2
        return (ann.p2 - ann.p1).manhattanLength() >= 3

    # ---------- 文字标注 ----------
    def _begin_text(self, pos, pos_w):
        ed = _TextInput(self)
        f = QFont()
        f.setPointSizeF(max(8.0, 14.0))
        ed.setFont(f)
        ed.setStyleSheet(
            f"background:transparent; border:1px dashed {self._color.name()};"
            f" color:{self._color.name()}; padding:1px;")
        ed.move(pos_w)
        ed.resize(220, ed.sizeHint().height())
        ed.committed.connect(lambda t, e=ed, pt=pos, c=QColor(self._color):
                             self._commit_text(t, e, pt, c))
        ed.cancelled.connect(lambda e=ed: self._cancel_text(e))
        ed.show()
        ed.setFocus()
        self._text_edit = ed

    def _commit_text(self, text, ed, pos, color):
        if self._text_edit is None:
            return
        self._text_edit = None
        if text.strip():
            ann = _Annotation("text", color, self._width)
            ann.p1 = pos
            ann.text = text
            f = QFont()
            f.setPointSizeF(max(6.0, 14.0 / self._scale))   # 显示 14pt 烘焙到图片像素
            ann.font = f
            self._annotations.append(ann)
        ed.deleteLater()
        self.update()

    def _cancel_text(self, ed):
        self._text_edit = None
        ed.deleteLater()
        self.update()


class ImageEditorDialog(QDialog):
    """在应用内编辑一张已落地的图片(发送框里的截图缩略图双击打开)。

    顶部工具条复用截图时的标注工具(矩形/椭圆/箭头/画笔/文字 + 颜色 + 线宽 + 撤销),
    并额外提供裁剪与旋转。确认后把结果另存为新 PNG, result_path 给出新路径。
    """

    def __init__(self, parent, image_path):
        super().__init__(parent)
        self.setWindowTitle("编辑图片")
        self.setStyleSheet(STYLE)
        self.result_path = None
        self._src_path = image_path
        self.canvas = _EditorCanvas(QPixmap(image_path))

        root = QVBoxLayout(self)
        root.setContentsMargins(0, 0, 0, 0)
        root.setSpacing(0)
        root.addWidget(self._build_toolbar())

        scroll = QScrollArea()
        scroll.setWidgetResizable(False)
        scroll.setAlignment(Qt.AlignmentFlag.AlignCenter)
        scroll.setStyleSheet("QScrollArea { background:#15171C; border:none; }")
        holder = QWidget()
        holder.setStyleSheet("background:#15171C;")
        hl = QVBoxLayout(holder)
        hl.setContentsMargins(16, 16, 16, 16)
        hl.addWidget(self.canvas, 0, Qt.AlignmentFlag.AlignCenter)
        scroll.setWidget(holder)
        root.addWidget(scroll, 1)

        self.canvas.on_changed = lambda: holder.adjustSize()
        screen = QApplication.primaryScreen()
        avail = screen.availableGeometry() if screen else QRect(0, 0, 1100, 800)
        self.resize(min(avail.width() - 80, self.canvas.width() + 120),
                    min(avail.height() - 80, self.canvas.height() + 150))

    def _build_toolbar(self):
        bar = QFrame()
        bar.setObjectName("shotToolbar")
        bar.setStyleSheet(
            "#shotToolbar { background:#23262E; border-bottom:1px solid #3A3F4B; }"
            " QToolButton { background:transparent; color:#E6E8EC; border:none;"
            " border-radius:6px; padding:5px 7px; font-size:15px; }"
            " QToolButton:hover { background:#343945; }"
            " QToolButton:checked { background:#5B8CFF; color:#FFFFFF; }")
        lay = QHBoxLayout(bar)
        lay.setContentsMargins(8, 6, 8, 6)
        lay.setSpacing(2)
        self._tool_btns = {}

        def add_tool(key, tip):
            b = QToolButton(bar)
            b.setIcon(_tool_icon(key))
            b.setIconSize(QSize(18, 18))
            b.setToolTip(tip)
            b.setCheckable(True)
            b.setCursor(Qt.CursorShape.PointingHandCursor)
            b.clicked.connect(lambda _=False, k=key: self._select_tool(k))
            lay.addWidget(b)
            self._tool_btns[key] = b

        add_tool("rect", "矩形")
        add_tool("ellipse", "椭圆")
        add_tool("arrow", "箭头")
        add_tool("pen", "画笔")
        add_tool("text", "文字")

        self._add_sep(lay)
        self._color_btns = []
        for c in ScreenshotOverlay.COLORS:
            b = QToolButton(bar)
            b.setCheckable(True)
            b.setCursor(Qt.CursorShape.PointingHandCursor)
            b.setFixedSize(20, 20)
            b.setStyleSheet(
                f"QToolButton {{ background:{c}; border:1px solid #555; border-radius:10px; }}"
                f" QToolButton:checked {{ border:2px solid #5B8CFF; }}")
            b.clicked.connect(lambda _=False, col=c: self._select_color(col))
            lay.addWidget(b)
            self._color_btns.append((c, b))
        self._color_btns[0][1].setChecked(True)

        self._add_sep(lay)
        self._width_btns = []
        for label, w in ScreenshotOverlay.WIDTHS:
            b = QToolButton(bar)
            b.setText(label)
            b.setCheckable(True)
            b.setCursor(Qt.CursorShape.PointingHandCursor)
            b.clicked.connect(lambda _=False, ww=w: self._select_width(ww))
            if w == 4:
                b.setChecked(True)
            lay.addWidget(b)
            self._width_btns.append((w, b))

        self._add_sep(lay)
        self._btn_crop = QToolButton(bar)
        self._btn_crop.setText("裁剪")
        self._btn_crop.setCheckable(True)
        self._btn_crop.setToolTip("裁剪（拖动选框，再次点击或回车应用，Esc 取消）")
        self._btn_crop.setCursor(Qt.CursorShape.PointingHandCursor)
        self._btn_crop.clicked.connect(self._toggle_crop)
        lay.addWidget(self._btn_crop)
        b_rl = QToolButton(bar); b_rl.setText("↺"); b_rl.setToolTip("向左旋转 90°")
        b_rl.setCursor(Qt.CursorShape.PointingHandCursor)
        b_rl.clicked.connect(lambda: self._rotate(False)); lay.addWidget(b_rl)
        b_rr = QToolButton(bar); b_rr.setText("↻"); b_rr.setToolTip("向右旋转 90°")
        b_rr.setCursor(Qt.CursorShape.PointingHandCursor)
        b_rr.clicked.connect(lambda: self._rotate(True)); lay.addWidget(b_rr)
        b_undo = QToolButton(bar); b_undo.setText("⟲撤销"); b_undo.setToolTip("撤销 (Ctrl+Z)")
        b_undo.setCursor(Qt.CursorShape.PointingHandCursor)
        b_undo.clicked.connect(self.canvas.undo); lay.addWidget(b_undo)

        lay.addStretch()
        b_cancel = QToolButton(bar); b_cancel.setText("✕ 取消")
        b_cancel.setCursor(Qt.CursorShape.PointingHandCursor)
        b_cancel.setStyleSheet("QToolButton { color:#FF6B6B; }")
        b_cancel.clicked.connect(self.reject); lay.addWidget(b_cancel)
        b_ok = QToolButton(bar); b_ok.setText("✓ 完成")
        b_ok.setCursor(Qt.CursorShape.PointingHandCursor)
        b_ok.setStyleSheet("QToolButton { color:#2ECC71; font-weight:bold; }")
        b_ok.clicked.connect(self._confirm); lay.addWidget(b_ok)
        return bar

    def _add_sep(self, lay):
        sep = QFrame()
        sep.setFixedWidth(1)
        sep.setStyleSheet("background:#3A3F4B;")
        lay.addWidget(sep)

    def _select_tool(self, key):
        self.canvas.set_tool(key)
        if self.canvas._crop_mode:
            self._set_crop_checked(False)
            self.canvas.cancel_crop()
        for k, b in self._tool_btns.items():
            b.setChecked(k == key)

    def _select_color(self, c):
        self.canvas.set_color(c)
        for cc, b in self._color_btns:
            b.setChecked(cc == c)

    def _select_width(self, w):
        self.canvas.set_width(w)
        for ww, b in self._width_btns:
            b.setChecked(ww == w)

    def _toggle_crop(self):
        self.canvas.toggle_crop()
        self._set_crop_checked(self.canvas._crop_mode)
        if self.canvas._crop_mode:
            for b in self._tool_btns.values():
                b.setChecked(False)

    def _set_crop_checked(self, on):
        self._btn_crop.setChecked(on)

    def _rotate(self, cw):
        self.canvas.rotate(cw)
        self._set_crop_checked(False)

    def keyPressEvent(self, e):
        if e.key() == Qt.Key.Key_Escape:
            if self.canvas._crop_mode:
                self.canvas.cancel_crop()
                self._set_crop_checked(False)
            else:
                self.reject()
            return
        if e.key() in (Qt.Key.Key_Return, Qt.Key.Key_Enter):
            if self.canvas._crop_mode:
                self.canvas.apply_crop()
                self._set_crop_checked(False)
            else:
                self._confirm()
            return
        if e.key() in (Qt.Key.Key_Backspace, Qt.Key.Key_Delete):
            self.canvas.delete_selected()
            return
        if e.key() == Qt.Key.Key_Z and (e.modifiers() & Qt.KeyboardModifier.ControlModifier):
            self.canvas.undo()
            return
        super().keyPressEvent(e)

    def _confirm(self):
        try:
            IMG_DIR.mkdir(parents=True, exist_ok=True)
            out = IMG_DIR / f"stage_{int(time.time() * 1000)}_{os.getpid()}_edit.png"
            self.canvas.result_pixmap().save(str(out), "PNG")
            self.result_path = str(out)
        except Exception:
            self.result_path = None
        self.accept()


# ===================================================================
#  协议层: 在同一 TCP 端口上传输三类消息
#    kind="file"  -> 普通文件, 落到 机器名/ 子目录 (保持原行为)
#    kind="text"  -> 聊天文字
#    kind="image" -> 聊天图片(截图/粘贴)
#  统一帧格式: MAGIC | 4字节头长 | JSON头 | 可选二进制负载
# ===================================================================
class Discovery:
    def __init__(self, hostname, on_peers_change):
        self.hostname = hostname
        self.on_peers_change = on_peers_change
        self.peers = {}
        self.lock = threading.Lock()
        self.running = True
        self.local_ip = get_local_ip()   # 主 LAN IP（已过滤 VPN）
        self._reply_times = {}           # ip -> 上次单播回应时间，用于限速
        # 稳定的本机设备标识：同一台机器即使有多个 IP，对端也能归并成一台
        self.uid = get_setting("device_uid", None)
        if not self.uid:
            self.uid = uuid.uuid4().hex[:12]
            set_setting("device_uid", self.uid)

    # ---- 多网卡/VPN 感知 ----
    def _all_ips(self):
        """本机所有 IPv4（含 VPN），用于过滤自身广播。"""
        return _all_machine_ips()

    def _lan_ips(self):
        """只返回真实 LAN IP（跳过 VPN/隧道地址），用于 announce。"""
        result = [ip for ip in self._all_ips()
                  if not ip.startswith("127.") and ip != "0.0.0.0" and not _is_vpn_ip(ip)]
        return result or [self.local_ip]

    def _best_announce_ip(self, target_ip=None):
        """选最合适的本机 LAN IP 来 announce（优先与 target 同 /24 子网）。"""
        lan = self._lan_ips()
        if target_ip:
            prefix = ".".join(target_ip.split(".")[:3])
            for ip in lan:
                if ".".join(ip.split(".")[:3]) == prefix:
                    return ip
        return lan[0] if lan else self.local_ip

    def _make_msg(self, lan_ip=None):
        if lan_ip is None:
            lan_ip = self._best_announce_ip()
        return json.dumps({
            "type": "announce", "name": self.hostname,
            "ip": lan_ip, "port": TRANSFER_PORT, "uid": self.uid,
        }).encode("utf-8")

    # ---- 生命周期 ----
    def start(self):
        threading.Thread(target=self._broadcaster, daemon=True).start()
        threading.Thread(target=self._listener, daemon=True).start()
        threading.Thread(target=self._reaper, daemon=True).start()

    def stop(self):
        self.running = False

    # ---- 主动发现 ----
    def ping_known(self, ips):
        """启动后向历史已知设备单播，加速初始发现（含 Windows 防火墙场景）。"""
        def _do():
            time.sleep(0.8)
            try:
                s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
                all_mine = self._all_ips()
                for ip in ips:
                    if ip not in all_mine:
                        try:
                            s.sendto(self._make_msg(self._best_announce_ip(ip)),
                                     (ip, DISCOVERY_PORT))
                        except Exception:
                            pass
                s.close()
            except Exception:
                pass
        threading.Thread(target=_do, daemon=True).start()

    def force_broadcast(self):
        """立即广播 + 单播到所有当前已知对端（刷新按钮触发）。"""
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            s.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1)
            # 每个 LAN IP 各自广播
            for lan_ip in self._lan_ips():
                msg = self._make_msg(lan_ip)
                for addr in get_broadcast_addrs():
                    try:
                        s.sendto(msg, (addr, DISCOVERY_PORT))
                    except Exception:
                        pass
            # 单播到已知对端
            with self.lock:
                peer_ips = list(self.peers.keys())
            all_mine = self._all_ips()
            for ip in peer_ips:
                if ip not in all_mine:
                    try:
                        s.sendto(self._make_msg(self._best_announce_ip(ip)),
                                 (ip, DISCOVERY_PORT))
                    except Exception:
                        pass
            s.close()
        except Exception:
            pass

    def update_name(self, new_name: str):
        """更新广播名称并立即重播，让对端即时感知改名。"""
        self.hostname = new_name
        threading.Thread(target=self.force_broadcast, daemon=True).start()

    def _unicast_reply(self, target_ip):
        """收到对端广播后，单播回应，穿透 Windows 防火墙。"""
        now = time.time()
        if now - self._reply_times.get(target_ip, 0) < BROADCAST_INTERVAL:
            return
        self._reply_times[target_ip] = now
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            # 选与 target 同子网的本机 IP 来 announce，对方能直接回连
            s.sendto(self._make_msg(self._best_announce_ip(target_ip)),
                     (target_ip, DISCOVERY_PORT))
            s.close()
        except Exception:
            pass

    def note_active_peer(self, ip, name=None, port=None, uid=None):
        """收到对端入站连接(传输/聊天)即视为其在线。UDP announce 可能因防火墙
        或单向可达而收不到, 但既然对方能连上来, 它必定在线且可回连——据此立即
        刷新 presence, 并回敬一次单播 announce, 引导后续双向发现持续生效。"""
        if not ip or ip in self._all_ips():
            return
        with self.lock:
            p = self.peers.get(ip, {})
            p["last"] = time.time()
            p["name"] = name or p.get("name", ip)
            p["port"] = port or p.get("port", TRANSFER_PORT)
            if uid:
                p["uid"] = uid
            p.setdefault("uid", None)
            p["_online"] = True
            self.peers[ip] = p
        self.on_peers_change(self.snapshot())
        # 回敬单播 announce: 对方收到后会再单播回应, 我方据此持续看到它在线
        threading.Thread(target=self._unicast_reply, args=(ip,),
                         daemon=True).start()

    def _broadcaster(self):
        """每个真实 LAN IP 分别广播 announce，VPN 开启时依然能发现对端。"""
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1)
        while self.running:
            extra_subnets = get_setting("extra_subnets", [])
            for lan_ip in self._lan_ips():   # 每轮重新枚举，自动感知 VPN 状态变化
                msg = self._make_msg(lan_ip)
                # 该网卡的子网广播 + 全网广播
                parts = lan_ip.split(".")
                targets = {"255.255.255.255"}
                if len(parts) == 4:
                    targets.add(f"{parts[0]}.{parts[1]}.{parts[2]}.255")
                for sub in extra_subnets:
                    sub = sub.strip()
                    if sub:
                        targets.add(f"{sub}.255")
                for addr in targets:
                    try:
                        s.sendto(msg, (addr, DISCOVERY_PORT))
                    except Exception:
                        pass
            time.sleep(BROADCAST_INTERVAL)

    def _listener(self):
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        s.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1)
        try:
            s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEPORT, 1)
        except (AttributeError, OSError):
            pass
        s.bind(("", DISCOVERY_PORT))
        s.settimeout(1.0)
        while self.running:
            try:
                data, addr = s.recvfrom(2048)
                info = json.loads(data.decode("utf-8"))
                if info.get("type") != "announce":
                    continue
                ip = info.get("ip", addr[0])
                if ip in self._all_ips():   # 过滤自身所有 IP（含 VPN IP）
                    continue
                with self.lock:
                    self.peers[ip] = {
                        "name": info.get("name", ip),
                        "port": info.get("port", TRANSFER_PORT),
                        "uid": info.get("uid"),
                        "last": time.time(),
                    }
                self.on_peers_change(self.snapshot())
                threading.Thread(target=self._unicast_reply, args=(ip,),
                                 daemon=True).start()
            except socket.timeout:
                continue
            except Exception:
                continue

    def _reaper(self):
        while self.running:
            now = time.time()
            changed = False
            with self.lock:
                for ip, p in list(self.peers.items()):
                    online = (now - p["last"]) <= PEER_TIMEOUT
                    if p.get("_online") != online:
                        p["_online"] = online
                        changed = True
            if changed:
                self.on_peers_change(self.snapshot())
            time.sleep(1.5)

    def snapshot(self):
        now = time.time()
        with self.lock:
            out = {}
            for ip, p in self.peers.items():
                out[ip] = {
                    "name": p["name"], "port": p["port"],
                    "uid": p.get("uid"),
                    "online": (now - p["last"]) <= PEER_TIMEOUT,
                }
            return out


class Receiver:
    """统一接收: 文件 / 文字 / 图片。"""
    def __init__(self, on_file, on_chat, on_log, on_progress=None,
                 get_recv_confirm=None, on_recv_started=None, on_recv_done=None,
                 on_recv_cancelled=None, on_peer_seen=None):
        self.on_file = on_file             # (path, sender)
        self.on_chat = on_chat             # (sender_name, sender_ip, kind, payload)
        self.on_log = on_log
        self.on_progress = on_progress     # (recv_id, filename, done, total, speed)
        self.get_recv_confirm = get_recv_confirm or (lambda: False)
        self.on_recv_started = on_recv_started    # (recv_id, sender, sender_ip, meta_json)
        self.on_recv_done = on_recv_done          # (recv_id)
        self.on_recv_cancelled = on_recv_cancelled  # (recv_id)
        self.on_peer_seen = on_peer_seen   # (sender_ip, name, uid, port) 入站连接即在线
        self.running = True

    def start(self):
        threading.Thread(target=self._serve, daemon=True).start()

    def stop(self):
        self.running = False

    def _serve(self):
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        try:
            s.bind(("", TRANSFER_PORT))
            s.listen(8)
            s.settimeout(1.0)
        except Exception as e:
            self.on_log(f"无法监听端口 {TRANSFER_PORT}: {e}", "error")
            return
        while self.running:
            try:
                conn, addr = s.accept()
            except socket.timeout:
                continue
            except Exception:
                continue
            threading.Thread(target=self._handle, args=(conn, addr),
                             daemon=True).start()

    def _handle(self, conn, addr):
        try:
            # 握手阶段设较短超时，挡住“连上却不发数据”的连接（slowloris）
            conn.settimeout(HANDSHAKE_TIMEOUT)
            if recv_exact(conn, 4) != MAGIC:
                return
            (hlen,) = struct.unpack(">I", recv_exact(conn, 4))
            if hlen <= 0 or hlen > MAX_HEADER:
                self.on_log(f"拒收异常头部({hlen} 字节)，来自 {addr[0]}", "error")
                return
            header = json.loads(recv_exact(conn, hlen).decode("utf-8"))
            kind = header.get("kind", "file")
            sender = header.get("sender", addr[0])
            sender_ip = addr[0]
            size = header.get("size", 0)

            # 对方能连上来 = 它一定在线且可回连; 据此立即刷新在线状态,
            # 不依赖可能被防火墙拦掉的 UDP 广播。带上 uid 以便多 IP 归并成一台。
            if self.on_peer_seen:
                try:
                    self.on_peer_seen(sender_ip, sender, header.get("uid"),
                                      header.get("port") or TRANSFER_PORT)
                except Exception:
                    pass

            if kind == "text":
                self.on_chat(sender, sender_ip, "text", header.get("text", ""))
                return

            # 进入数据阶段，放宽超时（覆盖正常传输与暂停；长时间无数据则判为中断）
            conn.settimeout(DATA_TIMEOUT)

            if kind == "batch":
                self._handle_batch(conn, header, sender, sender_ip)
                return

            # 只接受已知的 file / image 单条类型; 未知类型直接拒收,
            # 避免对端版本不一致时把整帧当成文件写成 file.bin。
            if kind not in ("file", "image"):
                self.on_log(
                    f"收到无法识别的消息(来自 {sender})。可能对方 LanTong 版本较旧，"
                    f"请让双方都更新到最新版本。", "error")
                return

            # file / image 都带二进制负载
            filename_hint = header.get("filename", "file.bin")
            single_recv_id = uuid.uuid4().hex[:10]
            if self.on_recv_started and size > 0:
                meta = [{"type": kind, "name": filename_hint, "size": size}]
                self.on_recv_started(single_recv_id, sender, sender_ip,
                                     json.dumps(meta, ensure_ascii=False))

            # 先确定落盘路径，再边收边写（不把整文件堆内存）
            confirm = False
            if kind == "image":
                IMG_DIR.mkdir(parents=True, exist_ok=True)
                dest = IMG_DIR / f"recv_{int(time.time()*1000)}.png"
            else:
                folder = safe_folder_name(sender)
                confirm = self.get_recv_confirm()
                dest_dir = (TEMP_RECV_DIR if confirm else globals()["RECV_ROOT"]) / folder
                dest_dir.mkdir(parents=True, exist_ok=True)
                filename = os.path.basename(filename_hint)
                dest = dest_dir / filename
                b, e = os.path.splitext(filename)
                i = 1
                while dest.exists():
                    dest = dest_dir / f"{b}_{i}{e}"
                    i += 1

            t_start = time.time()
            try:
                with open(dest, "wb") as f:
                    self._stream_n(conn, size, f, single_recv_id, filename_hint,
                                   0, size, t_start)
            except _TransferAborted:
                try:
                    Path(dest).unlink(missing_ok=True)
                except Exception:
                    pass
                self.on_log(f"{filename_hint} 传输被取消", "info")
                if self.on_recv_cancelled and size > 0:
                    self.on_recv_cancelled(single_recv_id)
                return

            if self.on_recv_done and size > 0:
                self.on_recv_done(single_recv_id)

            if kind == "image":
                self.on_chat(sender, sender_ip, "image", str(dest))
            elif confirm:
                # 告诉 UI 有待确认文件, kind=batch_staged
                staged_part = [{"type": "file", "name": filename,
                                "size": size, "path": str(dest),
                                "final_dir": str(globals()["RECV_ROOT"] / folder)}]
                self.on_log(f"待确认: {filename} · 来自 {sender}", "recv")
                self.on_chat(sender, sender_ip, "batch_staged",
                             json.dumps(staged_part, ensure_ascii=False))
            else:
                self.on_log(f"收到 {dest.name} · 来自 {sender} · {human_size(size)}", "recv")
                self.on_file(str(dest), sender)
        except Exception as e:
            self.on_log(f"接收失败: {e}", "error")
        finally:
            conn.close()

    def _handle_batch(self, conn, header, sender, sender_ip):
        """接收一批消息: header.parts 描述每个部件, 之后是各二进制负载顺序拼接。"""
        parts = header.get("parts", [])
        folder = safe_folder_name(sender)
        confirm = self.get_recv_confirm()
        out_parts = []          # 给 UI 的渲染部件 [{type, ...}]
        IMG_DIR.mkdir(parents=True, exist_ok=True)

        total_binary = sum(p.get("size", 0) for p in parts if p.get("type") in ("image", "file"))
        recv_bytes = 0
        t_start = time.time()
        first_fname = next((p.get("filename", p.get("type", "")) for p in parts
                            if p.get("type") in ("file", "image")), "")

        # 生成唯一接收 ID，通知 UI 立即显示占位动画
        recv_id = uuid.uuid4().hex[:10]
        if self.on_recv_started and total_binary > 0:
            meta = [
                {"type": p["type"],
                 "name": p.get("filename", "image.png") if p["type"] == "file" else "image.png",
                 "size": p.get("size", 0)}
                for p in parts if p.get("type") in ("file", "image")
            ]
            self.on_recv_started(recv_id, sender, sender_ip,
                                 json.dumps(meta, ensure_ascii=False))

        written_paths = []   # 记录已写盘的文件，用于取消时清理
        pending_on_file = []  # 自动接收的文件，提交确认后才通知 UI
        try:
            for part in parts:
                ptype = part.get("type")
                if ptype == "text":
                    out_parts.append({"type": "text", "text": part.get("text", "")})
                elif ptype == "image":
                    size = part.get("size", 0)
                    fn = f"recv_{int(time.time()*1000*1000)%10**13}.png"
                    path = IMG_DIR / fn
                    written_paths.append(path)   # 先登记，途中中断也能清理半截文件
                    with open(path, "wb") as f:
                        self._stream_n(conn, size, f, recv_id, first_fname,
                                       recv_bytes, total_binary, t_start)
                    recv_bytes += size
                    out_parts.append({"type": "image", "path": str(path)})
                elif ptype == "file":
                    size = part.get("size", 0)
                    filename = os.path.basename(part.get("filename", "file.bin"))
                    if confirm:
                        dest_dir = TEMP_RECV_DIR / folder
                    else:
                        dest_dir = globals()["RECV_ROOT"] / folder
                    dest_dir.mkdir(parents=True, exist_ok=True)
                    rel = safe_relpath(part.get("relpath"))
                    dest = (dest_dir / rel) if rel else None
                    # 防目录穿越：解析后必须仍在 dest_dir 之内，否则退回扁平文件名
                    if dest is not None:
                        try:
                            inside = os.path.commonpath(
                                [dest.resolve(strict=False),
                                 dest_dir.resolve(strict=False)]) == str(dest_dir.resolve(strict=False))
                        except Exception:
                            inside = False
                        if inside:
                            dest.parent.mkdir(parents=True, exist_ok=True)
                        else:
                            dest = None
                    if dest is None:
                        dest = dest_dir / filename
                        b, e = os.path.splitext(filename)
                        i = 1
                        while dest.exists():
                            dest = dest_dir / f"{b}_{i}{e}"
                            i += 1
                    written_paths.append(dest)   # 先登记，途中中断也能清理半截文件
                    with open(dest, "wb") as f:
                        self._stream_n(conn, size, f, recv_id, filename,
                                       recv_bytes, total_binary, t_start)
                    recv_bytes += size
                    final_dir = str(globals()["RECV_ROOT"] / folder) if confirm else ""
                    out_parts.append({"type": "file", "name": filename,
                                      "size": size, "path": str(dest),
                                      "staged": confirm,
                                      "final_dir": final_dir,
                                      "relpath": part.get("relpath")})
                    if not confirm:
                        pending_on_file.append(str(dest))

            # 关键：读完声明的全部字节后，还必须收到 COMMIT 标记才视为成功。
            # 发送方取消时不发送它，接收方据此丢弃数据——即便数据已全部送达 TCP 缓冲区。
            if self._recv_n(conn, 1) != COMMIT:
                raise _TransferAborted("未收到完成标记")

        except _TransferAborted:
            # 发送方取消：删除已写盘的残缺文件，通知 UI 撤销占位符
            for p in written_paths:
                try:
                    Path(p).unlink(missing_ok=True)
                except Exception:
                    pass
            self.on_log(f"来自 {sender} 的传输被取消", "info")
            if self.on_recv_cancelled and total_binary > 0:
                self.on_recv_cancelled(recv_id)
            return

        # 走到这里说明已收到完成标记，才把文件交给 UI / 归档
        for dest_path in pending_on_file:
            self.on_file(dest_path, sender)
        self.on_log(f"收到一批消息 · 来自 {sender} · {len(parts)} 项", "recv")
        if self.on_recv_done and total_binary > 0:
            self.on_recv_done(recv_id)
        # 文字/图片永远自动接收; 仅文件在"手动确认"模式下需要确认
        auto_parts = [p for p in out_parts if p.get("type") in ("text", "image")]
        raw_files = [p for p in out_parts if p.get("type") == "file"]
        # 把同一文件夹(带 relpath)的文件合并成一个文件夹卡片, 接收方看到的是文件夹
        dest_base = (TEMP_RECV_DIR if confirm else globals()["RECV_ROOT"]) / folder
        groups, loose = {}, []
        for fp in raw_files:
            rel = fp.get("relpath")
            top = str(rel).replace("\\", "/").split("/")[0] if rel else None
            if top:
                groups.setdefault(top, []).append(fp)
            else:
                loose.append(fp)
        file_parts = []
        for top, members in groups.items():
            file_parts.append({
                "type": "file", "is_folder": True,
                "name": f"{top}/（{len(members)} 个文件）",
                "size": sum(m.get("size", 0) for m in members),
                "path": str(dest_base / top),
                "staged": confirm,
                "final_dir": str(globals()["RECV_ROOT"] / folder) if confirm else "",
            })
        file_parts.extend(loose)
        if auto_parts:
            self.on_chat(sender, sender_ip, "batch",
                         json.dumps(auto_parts, ensure_ascii=False))
        if file_parts:
            self.on_chat(sender, sender_ip,
                         "batch_staged" if confirm else "batch",
                         json.dumps(file_parts, ensure_ascii=False))

    def _recv_n_progress(self, conn, n, recv_id, fname, base_done, total, t_start):
        """接收 n 字节(小数据/标记用), 同时上报进度。连接关闭或超时则抛出 _TransferAborted。"""
        data = bytearray()
        while len(data) < n:
            try:
                chunk = conn.recv(min(CHUNK, n - len(data)))
            except socket.timeout:
                raise _TransferAborted(f"接收超时，已收 {len(data)}/{n} 字节")
            if not chunk:
                raise _TransferAborted(f"连接提前关闭，已收 {len(data)}/{n} 字节")
            data.extend(chunk)
            if self.on_progress and total > 0:
                done = base_done + len(data)
                elapsed = time.time() - t_start
                speed = done / elapsed if elapsed > 0.01 else 0
                self.on_progress(recv_id, fname, done, total, speed)
        return bytes(data)

    def _recv_n(self, conn, n):
        return self._recv_n_progress(conn, n, "", "", 0, 0, time.time())

    def _stream_n(self, conn, n, fileobj, recv_id, fname, base_done, total, t_start):
        """接收 n 字节并直接写入 fileobj（边收边写，不在内存里堆整文件）。
        连接提前关闭或超时则抛出 _TransferAborted。"""
        got = 0
        while got < n:
            try:
                chunk = conn.recv(min(CHUNK, n - got))
            except socket.timeout:
                raise _TransferAborted(f"接收超时，已收 {got}/{n} 字节")
            if not chunk:
                raise _TransferAborted(f"连接提前关闭，已收 {got}/{n} 字节")
            fileobj.write(chunk)
            got += len(chunk)
            if self.on_progress and total > 0:
                done = base_done + got
                elapsed = time.time() - t_start
                speed = done / elapsed if elapsed > 0.01 else 0
                self.on_progress(recv_id, fname, done, total, speed)
        return got


def _my_uid():
    """本机稳定设备标识(与 Discovery 共用 settings 里的 device_uid)。
    随传输头一起发出, 接收方据此把同一台机器的多个 IP 归并成一台。"""
    return get_setting("device_uid", None)


def _send_frame(peer_ip, peer_port, header, payload=b""):
    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    s.settimeout(10.0)
    s.connect((peer_ip, peer_port))
    s.settimeout(None)
    hb = json.dumps(header).encode("utf-8")
    s.sendall(MAGIC)
    s.sendall(struct.pack(">I", len(hb)))
    s.sendall(hb)
    if payload:
        s.sendall(payload)
    s.close()


def send_text(text, peer_ip, peer_port, sender_name, on_log):
    try:
        _send_frame(peer_ip, peer_port,
                    {"kind": "text", "sender": sender_name, "uid": _my_uid(),
                     "text": text})
        return True
    except Exception as e:
        on_log(f"消息发送失败: {e}", "error")
        return False


def send_image_bytes(data, peer_ip, peer_port, sender_name, on_log):
    try:
        _send_frame(peer_ip, peer_port,
                    {"kind": "image", "sender": sender_name, "uid": _my_uid(),
                     "size": len(data), "filename": "image.png"}, data)
        return True
    except Exception as e:
        on_log(f"图片发送失败: {e}", "error")
        return False


def send_file(filepath, peer_ip, peer_port, sender_name, on_log):
    try:
        filepath = Path(filepath)
        with open(filepath, "rb") as f:
            data = f.read()
        _send_frame(peer_ip, peer_port,
                    {"kind": "file", "sender": sender_name, "uid": _my_uid(),
                     "filename": filepath.name, "size": len(data)}, data)
        on_log(f"已发送 {filepath.name} → {peer_ip}", "send")
        return True
    except Exception as e:
        on_log(f"发送 {filepath.name} 失败: {e}", "error")
        return False


def send_batch(items, peer_ip, peer_port, sender_name, on_log,
               on_progress=None, first_name="", ctrl: "TransferControl | None" = None):
    """
    一次性发送一批内容(文字/图片/文件)作为单个消息块。
    ctrl: TransferControl 实例，可在发送途中暂停/取消。
    on_progress(filename, done_bytes, total_bytes, speed_bps) 每 CHUNK 回调一次。
    返回 True=完成, False=失败/取消。
    """
    s = None
    try:
        parts = []
        # sources: [(kind, payload, size)]  kind="mem"(内存字节) | "file"(磁盘路径)
        sources = []
        source_names = []
        for it in items:
            if ctrl and ctrl.is_cancelled:
                return "cancelled"
            t = it["type"]
            if t == "text":
                parts.append({"type": "text", "text": it["text"]})
            elif t == "image":
                if "bytes" in it:                     # 截图等：已在内存
                    data = it["bytes"]
                    parts.append({"type": "image", "size": len(data)})
                    sources.append(("mem", data, len(data)))
                    source_names.append(it.get("path", "image.png"))
                else:                                  # 磁盘图片：流式发送
                    p = Path(it["path"])
                    size = p.stat().st_size
                    parts.append({"type": "image", "size": size})
                    sources.append(("file", p, size))
                    source_names.append(it["path"])
            elif t == "file":
                p = Path(it["path"])
                size = p.stat().st_size               # 只取大小，不把整文件读进内存
                part = {"type": "file", "filename": p.name, "size": size}
                if it.get("relpath"):
                    part["relpath"] = it["relpath"]
                parts.append(part)
                sources.append(("file", p, size))
                source_names.append(p.name)

        if ctrl and ctrl.is_cancelled:
            return "cancelled"

        header = {"kind": "batch", "sender": sender_name, "uid": _my_uid(),
                  "parts": parts}
        # 再次检查：连接之前若已取消则直接退出，避免 header 已发出而对方开始等待数据
        if ctrl and ctrl.is_cancelled:
            return "cancelled"
        s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        s.settimeout(15.0)
        s.connect((peer_ip, peer_port))
        s.settimeout(None)
        hb = json.dumps(header).encode("utf-8")
        s.sendall(MAGIC)
        s.sendall(struct.pack(">I", len(hb)))
        s.sendall(hb)

        total_bytes = sum(sz for _, _, sz in sources)
        sent_bytes = 0
        t_start = time.time()
        display_name = first_name or (source_names[0] if source_names else "")

        def report():
            if on_progress and total_bytes > 0:
                elapsed = time.time() - t_start
                speed = sent_bytes / elapsed if elapsed > 0.01 else 0
                on_progress(display_name, sent_bytes, total_bytes, speed)

        for (kind_s, payload, size), sname in zip(sources, source_names):
            if kind_s == "mem":
                mv = memoryview(payload)
                off = 0
                while off < size:
                    if ctrl and not ctrl.wait_if_paused():
                        s.close()
                        on_log("发送已取消", "info")
                        return "cancelled"
                    chunk = mv[off:off + CHUNK]
                    s.sendall(chunk)
                    off += len(chunk)
                    sent_bytes += len(chunk)
                    report()
            else:  # file —— 边读边发，不在内存里堆整文件
                with open(payload, "rb") as fh:
                    sent = 0
                    while sent < size:
                        if ctrl and not ctrl.wait_if_paused():
                            s.close()
                            on_log("发送已取消", "info")
                            return "cancelled"
                        chunk = fh.read(min(CHUNK, size - sent))
                        if not chunk:
                            # 文件在发送途中被截断/移动：不发 COMMIT，接收方据此丢弃
                            s.close()
                            on_log(f"{sname} 读取中断，发送失败", "error")
                            return "error"
                        s.sendall(chunk)
                        sent += len(chunk)
                        sent_bytes += len(chunk)
                        report()

        # 所有数据已写入连接。发送提交标记前做最后一次取消检查：
        # 不发 COMMIT 而直接关闭，接收方读不到完成标记即丢弃（即便数据已全部送达缓冲区）。
        if ctrl and ctrl.is_cancelled:
            s.close()
            on_log("发送已取消", "info")
            return "cancelled"
        s.sendall(COMMIT)
        s.close()
        on_log(f"已发送一批消息 → {peer_ip}（{len(parts)} 项）", "send")
        return "ok"
    except Exception as e:
        try:
            if s is not None:
                s.close()
        except Exception:
            pass
        on_log(f"批量发送失败: {e}", "error")
        return "error"


class _TransferAborted(Exception):
    """发送方中途取消连接，接收方收到不完整数据时抛出。"""


# ----------------------------- 传输控制器 -----------------------------
class TransferControl:
    """线程安全的发送暂停/取消控制器，由主线程写、发送线程读。"""
    def __init__(self):
        self._cancel = threading.Event()
        self._pause  = threading.Event()

    def cancel(self):
        self._cancel.set()
        self._pause.clear()   # 唤醒可能阻塞在暂停里的线程

    def pause(self):
        self._pause.set()

    def resume(self):
        self._pause.clear()

    @property
    def is_cancelled(self) -> bool:
        return self._cancel.is_set()

    @property
    def is_paused(self) -> bool:
        return self._pause.is_set()

    def wait_if_paused(self) -> bool:
        """暂停时阻塞，返回 False 表示已取消。"""
        while self._pause.is_set():
            if self._cancel.is_set():
                return False
            time.sleep(0.05)
        return not self._cancel.is_set()


# ----------------------------- Qt 信号桥 -----------------------------
class Signals(QObject):
    peers_changed = pyqtSignal(dict)
    log = pyqtSignal(str, str)
    chat_in = pyqtSignal(str, str, str, str)    # sender_name, sender_ip, kind, payload
    sent = pyqtSignal(str, str)                  # ip, payload(JSON) —— 发送成功后回主线程加气泡
    staged = pyqtSignal(str)                      # 截图完成后回主线程放入待发区(图片路径)
    win_hide = pyqtSignal()                       # 截图前隐藏窗口(主线程)
    win_show = pyqtSignal()                       # 截图后恢复窗口(主线程)
    recv_started  = pyqtSignal(str, str, str, str)          # recv_id, sender_name, sender_ip, meta_json
    recv_progress = pyqtSignal(str, str, int, int, float)   # recv_id, filename, done, total, speed_bps
    send_unit_progress = pyqtSignal(str, int, int, float)  # unit_id, done, total, speed
    send_unit_result = pyqtSignal(str, str, str)           # unit_id, status(ok/cancelled/error), reason
    recv_done = pyqtSignal(str)                             # recv_id
    recv_cancelled = pyqtSignal(str)                        # recv_id — 发送方取消传输


# ----------------------------- 聊天气泡 -----------------------------
def _open_path(path):
    system = platform.system()
    try:
        if system == "Darwin":
            subprocess.run(["open", path])
        elif system == "Windows":
            os.startfile(path)  # type: ignore
        else:
            subprocess.run(["xdg-open", path])
    except Exception:
        pass


class ClickableImage(QLabel):
    # 全局注册表: 发送方图片进度动画
    _registry: list = []
    _pending_transfer_paths: set = set()

    def __init__(self, path, pix):
        super().__init__()
        self.path = path
        self._pix_orig = pix          # 保留原图用于复制
        self._progress = 0.0
        self._speed = 0.0
        self._transferring = (path in ClickableImage._pending_transfer_paths)
        self.setPixmap(pix)
        self.setCursor(Qt.CursorShape.PointingHandCursor)
        self.setObjectName("chatImage")
        self.setFocusPolicy(Qt.FocusPolicy.ClickFocus)   # 允许键盘聚焦
        self.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
        self.customContextMenuRequested.connect(self._menu)
        ClickableImage._registry.append(self)
        self.destroyed.connect(self._unregister)

    def _unregister(self):
        try:
            ClickableImage._registry.remove(self)
        except ValueError:
            pass

    @classmethod
    def update_transfer(cls, path_key, progress, speed) -> bool:
        hit = False
        for w in list(cls._registry):
            if w._transferring and (w.path == path_key or Path(w.path).name == Path(path_key).name):
                w._progress = progress
                w._speed = speed
                w.update()
                hit = True
        return hit

    @classmethod
    def finish_all_transfers(cls):
        for w in list(cls._registry):
            if w._transferring:
                w._transferring = False
                w._progress = 1.0
                w.update()

    def paintEvent(self, event):
        super().paintEvent(event)
        if not self._transferring:
            return
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        p.fillRect(self.rect(), QColor(14, 17, 24, 160))
        cx, cy = self.width() // 2, self.height() // 2
        R_out, R_in = 22, 13
        p.setPen(QPen(QColor(255, 255, 255, 45), 1.5))
        p.setBrush(Qt.BrushStyle.NoBrush)
        p.drawEllipse(cx - R_out, cy - R_out, R_out * 2, R_out * 2)
        if self._progress > 0:
            p.setPen(Qt.PenStyle.NoPen)
            p.setBrush(_theme_accent(230))
            span = -int(self._progress * 360 * 16)
            p.drawPie(cx - R_out, cy - R_out, R_out * 2, R_out * 2, 90 * 16, span)
        p.setPen(Qt.PenStyle.NoPen)
        p.setBrush(QColor(14, 17, 24, 210))
        p.drawEllipse(cx - R_in, cy - R_in, R_in * 2, R_in * 2)
        if self._progress > 0:
            p.setPen(QColor(255, 255, 255, 230))
            f = QFont()
            f.setPixelSize(9)
            f.setBold(True)
            p.setFont(f)
            r = QRectF(cx - R_in, cy - R_in, R_in * 2, R_in * 2)
            p.drawText(r, Qt.AlignmentFlag.AlignCenter, f"{int(self._progress * 100)}%")
        if self._speed > 0:
            p.setPen(QColor(180, 190, 210, 210))
            f2 = QFont()
            f2.setPixelSize(10)
            p.setFont(f2)
            p.drawText(self.rect().adjusted(0, cy + R_out + 4, 0, 0),
                       Qt.AlignmentFlag.AlignHCenter | Qt.AlignmentFlag.AlignTop,
                       _human_speed(self._speed))
        p.end()

    def mousePressEvent(self, e):
        if e.button() == Qt.MouseButton.LeftButton:
            self.setFocus()

    def mouseDoubleClickEvent(self, e):
        # 双击聊天里的图片: 打开应用内编辑器标注/裁剪; 点"完成"后结果进剪贴板待粘贴
        if e.button() == Qt.MouseButton.LeftButton and not self._transferring:
            if self.path and os.path.exists(self.path):
                dlg = ImageEditorDialog(self.window(), self.path)
                if dlg.exec() and dlg.result_path:
                    pix = QPixmap(dlg.result_path)
                    if not pix.isNull():
                        QApplication.clipboard().setPixmap(pix)
                        from PyQt6.QtWidgets import QToolTip
                        QToolTip.showText(QCursor.pos(), "已复制到剪贴板，可粘贴")
                return
            _open_path(self.path)

    def keyPressEvent(self, e):
        if e.key() == Qt.Key.Key_C and e.modifiers() == Qt.KeyboardModifier.ControlModifier:
            self._copy_to_clipboard()
        else:
            super().keyPressEvent(e)

    def _copy_to_clipboard(self):
        from PyQt6.QtWidgets import QApplication as _App
        pix = QPixmap(self.path) if (self.path and os.path.exists(self.path)) else self._pix_orig
        if not pix.isNull():
            _App.clipboard().setPixmap(pix)

    def _menu(self, pos):
        m = QMenu(self)
        act_copy   = m.addAction("复制图片")
        act_save   = m.addAction("另存为…")
        m.addSeparator()
        act_open   = m.addAction("打开图片")
        act_folder = m.addAction("在文件夹中显示")
        chosen = m.exec(self.mapToGlobal(pos))
        if chosen == act_copy:
            self._copy_to_clipboard()
        elif chosen == act_save:
            self._save_as()
        elif chosen == act_open:
            _open_path(self.path)
        elif chosen == act_folder:
            self._reveal()

    def _save_as(self):
        from PyQt6.QtWidgets import QFileDialog as _QFD
        if not (self.path and os.path.exists(self.path)):
            return
        suffix = Path(self.path).suffix or ".png"
        default = f"截图_{int(time.time())}{suffix}"
        dest, _ = _QFD.getSaveFileName(self, "保存截图到…", default,
                                       "图片 (*.png *.jpg *.jpeg *.bmp);;所有文件 (*.*)")
        if dest:
            try:
                import shutil
                shutil.copy2(self.path, dest)
            except Exception:
                try:
                    Path(dest).write_bytes(Path(self.path).read_bytes())
                except Exception:
                    pass

    def _reveal(self):
        if not (self.path and os.path.exists(self.path)):
            return
        system = platform.system()
        try:
            if system == "Darwin":
                subprocess.run(["open", "-R", self.path])
            elif system == "Windows":
                subprocess.run(["explorer", "/select,", os.path.normpath(self.path)])
            else:
                subprocess.run(["xdg-open", str(Path(self.path).parent)])
        except Exception:
            pass


class FileCard(QFrame):
    """聊天里的文件卡片。
    传输中: 苹果风格环形进度覆盖 + 速度文字，整张卡片灰暗。
    完成后: 恢复正常亮色，点击即可打开。
    """

    # 全局注册表: 用于进度信号更新匹配的卡片
    _registry: list = []
    # action_send 在创建气泡前设置, FileCard.__init__ 读取后清空由 action_send 负责
    _pending_transfer_names: set = set()

    def __init__(self, name, size, path, mine):
        super().__init__()
        self.path = path
        self._fname = name
        self._progress = 0.0        # 0.0 – 1.0
        self._speed = 0.0           # bytes/sec
        self._transferring = (name in FileCard._pending_transfer_names)
        self._icon_pix = FileCard._load_icon(path, name)

        self.setObjectName("fileCardMine" if mine else "fileCard")
        self.setCursor(Qt.CursorShape.PointingHandCursor)
        self.setFocusPolicy(Qt.FocusPolicy.ClickFocus)
        self.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
        self.customContextMenuRequested.connect(self._menu)
        lay = QHBoxLayout(self)
        lay.setContentsMargins(52, 8, 14, 8)   # 左边留出图标/圆环空间
        lay.setSpacing(10)
        col = QVBoxLayout()
        col.setSpacing(2)
        nm = QLabel(name)
        nm.setObjectName("fileCardNameMine" if mine else "fileCardName")
        nm.setMaximumWidth(240)
        sz = QLabel(human_size(size) if size else "")
        sz.setObjectName("fileCardSizeMine" if mine else "fileCardSize")
        col.addWidget(nm)
        col.addWidget(sz)
        lay.addLayout(col, 1)

        FileCard._registry.append(self)
        self.destroyed.connect(self._unregister)

    @staticmethod
    def _load_icon(path: str, name: str) -> "QPixmap":
        """获取操作系统原生文件类型图标。"""
        try:
            from PyQt6.QtWidgets import QFileIconProvider
            from PyQt6.QtCore import QFileInfo, Qt
            provider = QFileIconProvider()
            target = path if (path and os.path.exists(path)) else None
            icon = provider.icon(QFileInfo(target or name or "file.bin"))
            # 尝试多种尺寸：Windows HiDPI 下 pixmap(32,32) 可能返回空
            for sz in (32, 48, 16, 64):
                pix = icon.pixmap(sz, sz)
                if not pix.isNull():
                    if sz != 32:
                        pix = pix.scaled(32, 32, Qt.AspectRatioMode.KeepAspectRatio,
                                         Qt.TransformationMode.SmoothTransformation)
                    return pix
            # Windows 兜底：通过 Win32 SHGetFileInfoW 直接获取图标
            if platform.system() == "Windows":
                pix = FileCard._win_ctypes_icon(target or name or "file.bin")
                if pix and not pix.isNull():
                    return pix
            pix = provider.icon(QFileIconProvider.IconType.File).pixmap(32, 32)
            return pix if not pix.isNull() else QPixmap()
        except Exception:
            return QPixmap()

    @staticmethod
    def _win_ctypes_icon(path: str) -> "QPixmap | None":
        """Windows: 用 Win32 SHGetFileInfoW 获取文件图标并转为 QPixmap（绕过 Qt 图标提供器）。"""
        try:
            import ctypes
            import ctypes.wintypes as wt
            SHGFI_ICON = 0x100
            SHGFI_LARGEICON = 0x0
            SHGFI_USEFILEATTRIBUTES = 0x10
            FILE_ATTRIBUTE_NORMAL = 0x80

            class SHFILEINFO(ctypes.Structure):
                _fields_ = [("hIcon", wt.HANDLE), ("iIcon", ctypes.c_int),
                             ("dwAttributes", wt.DWORD),
                             ("szDisplayName", ctypes.c_wchar * 260),
                             ("szTypeName", ctypes.c_wchar * 80)]

            info = SHFILEINFO()
            ret = ctypes.windll.shell32.SHGetFileInfoW(
                path, FILE_ATTRIBUTE_NORMAL, ctypes.byref(info), ctypes.sizeof(info),
                SHGFI_ICON | SHGFI_LARGEICON | SHGFI_USEFILEATTRIBUTES)
            if not ret or not info.hIcon:
                return None

            size = 32
            user32, gdi32 = ctypes.windll.user32, ctypes.windll.gdi32
            hdc_screen = user32.GetDC(None)
            hdc_mem = gdi32.CreateCompatibleDC(hdc_screen)

            class BITMAPINFOHEADER(ctypes.Structure):
                _fields_ = [("biSize", wt.DWORD), ("biWidth", ctypes.c_long),
                             ("biHeight", ctypes.c_long), ("biPlanes", wt.WORD),
                             ("biBitCount", wt.WORD), ("biCompression", wt.DWORD),
                             ("biSizeImage", wt.DWORD), ("biXPelsPerMeter", ctypes.c_long),
                             ("biYPelsPerMeter", ctypes.c_long),
                             ("biClrUsed", wt.DWORD), ("biClrImportant", wt.DWORD)]

            class BITMAPINFO(ctypes.Structure):
                _fields_ = [("bmiHeader", BITMAPINFOHEADER), ("bmiColors", wt.DWORD * 3)]

            bmi = BITMAPINFO()
            bmi.bmiHeader.biSize = ctypes.sizeof(BITMAPINFOHEADER)
            bmi.bmiHeader.biWidth = size
            bmi.bmiHeader.biHeight = -size  # top-down DIB
            bmi.bmiHeader.biPlanes = 1
            bmi.bmiHeader.biBitCount = 32
            bmi.bmiHeader.biCompression = 0  # BI_RGB

            p_bits = ctypes.c_void_p()
            hbm = gdi32.CreateDIBSection(hdc_mem, ctypes.byref(bmi), 0,
                                          ctypes.byref(p_bits), None, 0)
            old_bm = gdi32.SelectObject(hdc_mem, hbm)
            user32.DrawIconEx(hdc_mem, 0, 0, info.hIcon, size, size, 0, None, 3)  # DI_NORMAL

            buf = (ctypes.c_ubyte * (size * size * 4))()
            ctypes.memmove(buf, p_bits, size * size * 4)

            gdi32.SelectObject(hdc_mem, old_bm)
            gdi32.DeleteDC(hdc_mem)
            user32.ReleaseDC(None, hdc_screen)
            gdi32.DeleteObject(hbm)
            user32.DestroyIcon(info.hIcon)

            # GDI BGRA → Qt RGBA
            data = bytearray(buf)
            for i in range(0, len(data), 4):
                data[i], data[i + 2] = data[i + 2], data[i]

            from PyQt6.QtGui import QImage, QPixmap
            img = QImage(bytes(data), size, size, size * 4, QImage.Format.Format_RGBA8888)
            return QPixmap.fromImage(img)
        except Exception:
            return None

    def _unregister(self):
        try:
            FileCard._registry.remove(self)
        except ValueError:
            pass

    # ---- 进度控制 ----
    def set_progress(self, progress: float, speed: float):
        self._transferring = True
        self._progress = max(0.0, min(1.0, progress))
        self._speed = speed
        self.update()

    def set_done(self):
        # Windows 的 SHGetFileInfo 需要真实文件才能返回正确图标，传输完成后文件已存在，重新加载
        self._icon_pix = FileCard._load_icon(self.path, self._fname)
        self._transferring = False
        self._progress = 1.0
        self._speed = 0.0
        self.update()

    # ---- 交互 ----
    def mousePressEvent(self, e):
        if e.button() == Qt.MouseButton.LeftButton:
            self.setFocus()

    def mouseDoubleClickEvent(self, e):
        if e.button() == Qt.MouseButton.LeftButton:
            if not self._transferring and self.path and os.path.exists(self.path):
                _open_path(self.path)

    def _menu(self, pos):
        exists = bool(self.path and os.path.exists(self.path))
        m = QMenu(self)
        act_open   = m.addAction("打开文件")
        act_folder = m.addAction("在文件夹中显示")
        m.addSeparator()
        act_save   = m.addAction("另存为…")
        if not exists or self._transferring:
            act_open.setEnabled(False)
            act_folder.setEnabled(False)
            act_save.setEnabled(False)
        chosen = m.exec(self.mapToGlobal(pos))
        if chosen == act_open:
            _open_path(self.path)
        elif chosen == act_folder:
            self._reveal()
        elif chosen == act_save:
            self._save_as()

    def _reveal(self):
        if not (self.path and os.path.exists(self.path)):
            return
        try:
            if platform.system() == "Darwin":
                subprocess.run(["open", "-R", self.path])
            elif platform.system() == "Windows":
                subprocess.run(["explorer", "/select,", os.path.normpath(self.path)])
            else:
                subprocess.run(["xdg-open", str(Path(self.path).parent)])
        except Exception:
            pass

    def _save_as(self):
        if not (self.path and os.path.exists(self.path)):
            return
        from PyQt6.QtWidgets import QFileDialog as _QFD
        suffix = Path(self.path).suffix
        fname  = Path(self.path).name
        dest, _ = _QFD.getSaveFileName(self, "另存为…", fname,
                                       f"原格式 (*{suffix});;所有文件 (*.*)")
        if dest:
            try:
                import shutil as _sh
                _sh.copy2(self.path, dest)
            except Exception:
                pass

    # ---- 绘制苹果风格进度叠层 ----
    def paintEvent(self, event):
        super().paintEvent(event)
        cx, cy = 26, self.height() // 2

        if not self._transferring:
            if self._icon_pix and not self._icon_pix.isNull():
                p = QPainter(self)
                p.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform)
                size = 28
                p.drawPixmap(cx - size // 2, cy - size // 2, size, size, self._icon_pix)
                p.end()
            return

        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)

        # 1. 半透明灰暗蒙层 (让卡片变暗, 像 iOS 未下载的应用)
        p.fillRect(self.rect(), QColor(14, 17, 24, 170))

        # 2. 圆环位置 (左侧, 代替 📄 图标)
        R_out = 17   # 外径
        R_in  = 10   # 内径 (环宽 = R_out - R_in)

        # 3. 底轨 (淡色完整圆)
        p.setPen(QPen(QColor(255, 255, 255, 40), 1.0))
        p.setBrush(Qt.BrushStyle.NoBrush)
        p.drawEllipse(cx - R_out, cy - R_out, R_out * 2, R_out * 2)

        # 4. 进度扇形 (从 12 点顺时针) — Accent 蓝色填充
        if self._progress > 0:
            p.setPen(Qt.PenStyle.NoPen)
            p.setBrush(_theme_accent(230))
            span = -int(self._progress * 360 * 16)   # 顺时针为负
            p.drawPie(cx - R_out, cy - R_out, R_out * 2, R_out * 2, 90 * 16, span)

        # 5. 挖掉内圆 → 形成环形 (苹果环状进度设计)
        p.setPen(Qt.PenStyle.NoPen)
        p.setBrush(QColor(14, 17, 24, 215))
        p.drawEllipse(cx - R_in, cy - R_in, R_in * 2, R_in * 2)

        # 6. 环心百分比数字
        pct_str = f"{int(self._progress * 100)}"
        p.setPen(QColor(255, 255, 255, 220))
        pf = QFont()
        pf.setPixelSize(9)
        pf.setBold(True)
        p.setFont(pf)
        p.drawText(QRectF(cx - R_in + 1, cy - R_in + 1, (R_in - 1) * 2, (R_in - 1) * 2),
                   Qt.AlignmentFlag.AlignCenter, pct_str)

        # 7. 右侧实时网速
        if self._speed > 0:
            sf = QFont()
            sf.setPixelSize(11)
            sf.setBold(True)
            p.setFont(sf)
            p.setPen(QColor(255, 255, 255, 200))
            right = QRectF(cx + R_out + 8, 0,
                           self.width() - cx - R_out - 12, self.height())
            p.drawText(right,
                       Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter,
                       _human_speed(self._speed))

        p.end()

    # ---- 类方法: 由 MainWindow 信号调用 ----
    @classmethod
    def update_transfer(cls, filename: str, progress: float, speed: float) -> bool:
        """更新当前正在传输且文件名匹配的卡片（跳过已完成的旧卡片）。"""
        fname = Path(filename).name if filename else filename
        hit = False
        for card in list(cls._registry):
            if not card._transferring:
                continue
            if card._fname == fname or card._fname == filename:
                try:
                    card.set_progress(progress, speed)
                    hit = True
                except RuntimeError:
                    cls._registry.remove(card)
        return hit

    @classmethod
    def finish_all_transfers(cls):
        """结束所有正在传输的卡片动画（发送完成后调用）。"""
        for card in list(cls._registry):
            if card._transferring:
                try:
                    card.set_done()
                except RuntimeError:
                    cls._registry.remove(card)


class Bubble(QFrame):
    def __init__(self, kind, payload, mine, ts, name, pending=False):
        super().__init__()
        self.setObjectName("bubbleRow")
        row = QHBoxLayout(self)
        row.setContentsMargins(0, 4, 0, 4)

        col = QVBoxLayout()
        col.setSpacing(3)

        meta_text = f"{name} · {ts}"
        if pending:
            meta_text += "  ⏳ 离线发送"
        meta = QLabel(meta_text)
        meta.setObjectName("bubbleMeta")
        meta.setSizePolicy(QSizePolicy.Policy.Maximum, QSizePolicy.Policy.Preferred)
        meta.setAlignment(Qt.AlignmentFlag.AlignRight if mine
                          else Qt.AlignmentFlag.AlignLeft)

        body = QFrame()
        body.setObjectName("bubbleMine" if mine else "bubbleTheirs")
        body.setSizePolicy(QSizePolicy.Policy.Maximum, QSizePolicy.Policy.Preferred)
        bl = QVBoxLayout(body)
        bl.setContentsMargins(12, 9, 12, 9)
        bl.setSpacing(7)

        # 统一成 parts 列表渲染
        parts = self._normalize(kind, payload)
        for part in parts:
            self._add_part(bl, part, mine)

        col.addWidget(meta)
        col.addWidget(body)

        if mine:
            row.addStretch()
            row.addLayout(col)
        else:
            row.addLayout(col)
            row.addStretch()

    def _normalize(self, kind, payload):
        """把旧的 text/image 单条 与 新的 batch 统一成 parts 列表。"""
        if kind == "batch":
            try:
                return json.loads(payload)
            except Exception:
                return [{"type": "text", "text": "[消息解析失败]"}]
        if kind == "text":
            return [{"type": "text", "text": payload}]
        if kind == "image":
            return [{"type": "image", "path": payload}]
        if kind == "notice":
            return [{"type": "notice", "text": payload}]
        return [{"type": "text", "text": str(payload)}]

    def _add_part(self, bl, part, mine):
        t = part.get("type")
        if t == "text":
            txt = part.get("text", "")
            if not txt:
                return
            lbl = QLabel(txt)
            lbl.setObjectName("bubbleTextMine" if mine else "bubbleText")
            lbl.setWordWrap(True)
            lbl.setMaximumWidth(420)
            lbl.setTextInteractionFlags(Qt.TextInteractionFlag.TextSelectableByMouse)
            bl.addWidget(lbl)
        elif t == "image":
            path = part.get("path", "")
            pix = QPixmap(path)
            if not pix.isNull():
                if pix.width() > 320:
                    pix = pix.scaledToWidth(320, Qt.TransformationMode.SmoothTransformation)
                bl.addWidget(ClickableImage(path, pix))
            else:
                bl.addWidget(QLabel("[图片无法显示]"))
        elif t == "file":
            bl.addWidget(FileCard(part.get("name", "文件"),
                                  part.get("size", 0),
                                  part.get("path", ""), mine))
        elif t == "notice":
            txt = part.get("text", "")
            if not txt:
                return
            lbl = QLabel(txt)
            lbl.setObjectName("bubbleNotice")
            lbl.setWordWrap(True)
            lbl.setMaximumWidth(420)
            lbl.setStyleSheet("color:#e05a4f; font-size:12px;")
            lbl.setTextInteractionFlags(Qt.TextInteractionFlag.TextSelectableByMouse)
            bl.addWidget(lbl)


