class ThemeSwatch(QFrame):
    """主题选择卡片: 显示缩略色板，点击选中。"""

    def __init__(self, name, tdata, selected=False, on_click=None):
        super().__init__()
        self._name = name
        self._bg = QColor(tdata["swatch_bg"])
        self._ac = QColor(tdata["swatch_ac"])
        self._selected = selected
        self._on_click = on_click
        self.setFixedSize(72, 66)
        self.setCursor(Qt.CursorShape.PointingHandCursor)

    def set_selected(self, v: bool):
        self._selected = v
        self.update()

    def mousePressEvent(self, e):
        if e.button() == Qt.MouseButton.LeftButton and self._on_click:
            self._on_click(self._name)

    def paintEvent(self, event):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        lum = self._bg.lightness()
        is_light = lum > 160
        # 未选中时边框根据背景明暗自动适配
        if self._selected:
            border_c = self._ac
        else:
            border_c = QColor(self._bg).darker(130) if is_light else QColor("#50545E")
        p.setPen(QPen(border_c, 2))
        p.setBrush(self._bg)
        p.drawRoundedRect(2, 2, 68, 60, 10, 10)
        # 左侧 sidebar 条
        sb = QColor(self._bg)
        sb = sb.darker(115) if is_light else (sb.lighter(150) if lum < 40 else sb.darker(108))
        p.setPen(Qt.PenStyle.NoPen)
        path = QPainterPath()
        path.addRoundedRect(QRectF(3, 3, 16, 58), 9, 9)
        p.fillPath(path, sb)
        # 气泡 mine (accent)
        p.setBrush(self._ac)
        p.drawRoundedRect(34, 11, 28, 10, 5, 5)
        # 气泡 theirs (表面色)
        surf = QColor(self._bg).darker(112) if is_light else QColor(self._bg).lighter(148)
        p.setBrush(surf)
        p.drawRoundedRect(22, 27, 22, 9, 4, 4)
        # 底部 accent 进度条示意
        p.setBrush(self._ac.darker(110) if is_light else self._ac)
        p.drawRoundedRect(22, 44, 34, 4, 2, 2)
        # 选中对勾
        if self._selected:
            p.setBrush(self._ac)
            p.drawEllipse(52, 4, 14, 14)
            tick_c = QColor("#FFFFFF") if self._ac.lightness() < 160 else QColor("#000000")
            p.setPen(QPen(tick_c, 2))
            p.drawLine(55, 11, 58, 14)
            p.drawLine(58, 14, 63, 8)
        p.end()


