class NetworkDialog(QDialog):
    """让用户手动添加/删除广播网段，解决跨子网或 VPN 场景下发现不到设备的问题。"""

    def __init__(self, parent, on_saved=None):
        super().__init__(parent)
        self.setWindowTitle("广播网段设置")
        self.resize(420, 380)
        self.setStyleSheet(STYLE)
        self._extra = list(get_setting("extra_subnets", []))
        self._on_saved = on_saved
        self._build()

    def _build(self):
        lay = QVBoxLayout(self)
        lay.setContentsMargins(22, 20, 22, 18)
        lay.setSpacing(14)

        lay.addWidget(self._lbl("自动检测到的网段（只读）", "selfLabel"))
        auto = self._auto_subnets()
        auto_text = "  " + "    ".join(f"{s}.x" for s in auto) if auto else "  （未检测到）"
        lbl_auto = QLabel(auto_text)
        lbl_auto.setObjectName("selfIp")
        lbl_auto.setWordWrap(True)
        lay.addWidget(lbl_auto)

        sep = QFrame()
        sep.setFrameShape(QFrame.Shape.HLine)
        sep.setObjectName("dialogSep")
        lay.addWidget(sep)

        lay.addWidget(self._lbl("手动添加网段（填入前三段，如 192.168.100）", "selfLabel"))
        row = QHBoxLayout()
        row.setSpacing(8)
        self.field = QLineEdit()
        self.field.setObjectName("chatInput")
        self.field.setPlaceholderText("例：192.168.100")
        self.field.setFixedHeight(36)
        self.field.returnPressed.connect(self._add)
        row.addWidget(self.field)
        btn_add = QPushButton("添加")
        btn_add.setObjectName("miniBtn")
        btn_add.setFixedHeight(36)
        btn_add.setCursor(Qt.CursorShape.PointingHandCursor)
        btn_add.clicked.connect(self._add)
        row.addWidget(btn_add)
        lay.addLayout(row)

        lay.addWidget(self._lbl("已添加的自定义网段", "selfLabel"))
        self.list_area = QScrollArea()
        self.list_area.setWidgetResizable(True)
        self.list_area.setObjectName("chatScroll")
        self.list_area.setMinimumHeight(90)
        self.list_area.setMaximumHeight(140)
        self.list_canvas = QWidget()
        self.list_canvas.setObjectName("chatCanvas")
        self.list_vbox = QVBoxLayout(self.list_canvas)
        self.list_vbox.setContentsMargins(4, 4, 4, 4)
        self.list_vbox.setSpacing(4)
        self.list_area.setWidget(self.list_canvas)
        lay.addWidget(self.list_area)
        self._refresh_list()

        tip = QLabel(
            "通常无需手动添加——发现设备后会自动维护。\n"
            "使用 VPN 或设备跨子网时，可在此填写对方所在网段。")
        tip.setObjectName("selfIp")
        tip.setWordWrap(True)
        lay.addWidget(tip)

        lay.addStretch()
        btn_row = QHBoxLayout()
        btn_row.addStretch()
        btn_close = QPushButton("完成")
        btn_close.setObjectName("primary")
        btn_close.setCursor(Qt.CursorShape.PointingHandCursor)
        btn_close.clicked.connect(self.accept)
        btn_row.addWidget(btn_close)
        lay.addLayout(btn_row)

    def _lbl(self, text, obj):
        l = QLabel(text)
        l.setObjectName(obj)
        return l

    def _auto_subnets(self):
        extra, seen, result = set(self._extra), set(), []
        ips = set()
        try:
            for info in socket.getaddrinfo(socket.gethostname(), None):
                if info[0] == socket.AF_INET:
                    ips.add(info[4][0])
        except Exception:
            pass
        ips.add(get_local_ip())
        for ip in ips:
            if ip.startswith("127.") or ip == "0.0.0.0":
                continue
            parts = ip.split(".")
            if len(parts) == 4:
                subnet = f"{parts[0]}.{parts[1]}.{parts[2]}"
                if subnet not in seen and subnet not in extra:
                    seen.add(subnet)
                    result.append(subnet)
        return result

    def _refresh_list(self):
        while self.list_vbox.count():
            item = self.list_vbox.takeAt(0)
            if item.widget():
                item.widget().deleteLater()
        if not self._extra:
            lbl = QLabel("  （暂无自定义网段）")
            lbl.setObjectName("emptyChat")
            self.list_vbox.addWidget(lbl)
            return
        for idx, subnet in enumerate(self._extra):
            row_w = QWidget()
            rl = QHBoxLayout(row_w)
            rl.setContentsMargins(6, 2, 6, 2)
            rl.setSpacing(8)
            lbl = QLabel(f"{subnet}.x")
            lbl.setObjectName("selfIp")
            rl.addWidget(lbl)
            rl.addStretch()
            btn_del = QPushButton("删除")
            btn_del.setObjectName("miniBtn")
            btn_del.setFixedHeight(26)
            btn_del.setCursor(Qt.CursorShape.PointingHandCursor)
            btn_del.clicked.connect(lambda _, i=idx: self._remove(i))
            rl.addWidget(btn_del)
            self.list_vbox.addWidget(row_w)
        self.list_vbox.addStretch()

    def _add(self):
        raw = self.field.text().strip()
        raw = re.sub(r'\.(0+|x+|\d+)$', '', raw)   # 去掉末尾第四段（兼容多种输入格式）
        parts = raw.split(".")
        if len(parts) != 3 or not all(p.isdigit() and 0 <= int(p) <= 255 for p in parts):
            QMessageBox.warning(self, "格式错误",
                "请输入正确的网段前三段，例如：192.168.100")
            return
        if raw in self._extra:
            QMessageBox.information(self, "已存在", f"{raw} 已在列表中。")
            return
        self._extra.append(raw)
        set_setting("extra_subnets", self._extra)
        self.field.clear()
        self._refresh_list()
        if self._on_saved:
            self._on_saved()

    def _remove(self, idx):
        if 0 <= idx < len(self._extra):
            self._extra.pop(idx)
            set_setting("extra_subnets", self._extra)
            self._refresh_list()
            if self._on_saved:
                self._on_saved()


# ----------------------------- 输入框(支持粘贴/拖入图片与文件) -----------------------------
IMAGE_EXTS = (".png", ".jpg", ".jpeg", ".bmp", ".gif", ".webp", ".tiff")


def _extract_paths(mime):
    """从 QMimeData 中尽可能稳健地提取本地文件/文件夹路径。
    优先 urls; 再回退解析常见的 text/uri-list 与纯文本路径,
    以应对某些系统(尤其 macOS)复制文件时 hasUrls 不稳定的情况。"""
    paths = []
    try:
        if mime.hasUrls():
            for u in mime.urls():
                if u.isLocalFile():
                    p = u.toLocalFile()
                    if p:
                        paths.append(p)
    except Exception:
        pass
    if paths:
        return paths
    # 回退: text/uri-list
    try:
        if mime.hasFormat("text/uri-list"):
            raw = bytes(mime.data("text/uri-list")).decode("utf-8", "ignore")
            from urllib.parse import urlparse, unquote
            for line in raw.splitlines():
                line = line.strip()
                if not line or line.startswith("#"):
                    continue
                if line.startswith("file://"):
                    pr = urlparse(line)
                    p = unquote(pr.path)
                    if p:
                        paths.append(p)
    except Exception:
        pass
    if paths:
        return paths
    # 回退: 纯文本里就是一个存在的路径
    try:
        if mime.hasText():
            t = mime.text().strip()
            if t and ("/" in t or "\\" in t) and os.path.exists(t):
                paths.append(t)
    except Exception:
        pass
    return paths


class ChatInput(QTextEdit):
    sendRequested = pyqtSignal()
    imageAttached = pyqtSignal(str)           # 落地后的图片路径(粘贴/拖入/截图)
    pathsAttached = pyqtSignal(list)          # 拖入/粘贴的文件或文件夹路径

    def __init__(self):
        super().__init__()
        self.setObjectName("chatInput")
        self.setPlaceholderText(
            "输入消息，Enter 发送，Shift+Enter 换行。可直接粘贴/拖入截图(显示缩略图)与文件。")
        self.setMinimumHeight(96)
        self.setAcceptDrops(True)
        self._img_counter = 0
        # 资源名 -> 真实文件路径, 用于发送时还原
        self._img_map = {}

    def keyPressEvent(self, e):
        # Ctrl/Cmd+V: 自己处理粘贴, 保证图片/文件能稳健粘贴(与"粘贴"按钮一致)
        if e.matches(QKeySequence.StandardKey.Paste):
            self._paste_from_clipboard()
            return
        if e.key() in (Qt.Key.Key_Return, Qt.Key.Key_Enter):
            if e.modifiers() & Qt.KeyboardModifier.ShiftModifier:
                super().keyPressEvent(e)
            else:
                self.sendRequested.emit()
                return
        else:
            super().keyPressEvent(e)

    def _paste_from_clipboard(self):
        """统一粘贴入口(快捷键/右键都走这里): 文件URL → 附件; 图片 → 内嵌; 否则文本。"""
        cb = QApplication.clipboard()
        md = cb.mimeData() if cb is not None else None
        if md is None:
            return
        paths = _extract_paths(md)
        if paths:
            self.pathsAttached.emit(paths)
            return
        if md.hasImage():
            img = cb.image()          # 比 md.imageData() 更稳健
            if img is not None and not img.isNull():
                p = _save_qimage(img)
                if p:
                    self.imageAttached.emit(p)
                return
        if md.hasText():
            self.insertPlainText(md.text())

    def add_inline_image(self, path, at_end=False):
        """把一张图片以缩略图形式插入到输入框光标处。at_end=True 时插到末尾。"""
        from PyQt6.QtGui import QTextImageFormat, QImage as _QImage, QTextCursor as _TC
        img = _QImage(path)
        if img.isNull():
            return
        disp_w = min(160, img.width())
        ratio = disp_w / img.width() if img.width() else 1
        disp_h = int(img.height() * ratio)
        self._img_counter += 1
        res_name = f"lt_img_{self._img_counter}"
        thumb = img.scaledToWidth(disp_w, Qt.TransformationMode.SmoothTransformation)
        self.document().addResource(3, QUrl(res_name), thumb)  # 3 = ImageResource
        self._img_map[res_name] = path
        fmt = QTextImageFormat()
        fmt.setName(res_name)
        fmt.setWidth(disp_w)
        fmt.setHeight(disp_h)
        cur = self.textCursor()
        if at_end:
            cur.movePosition(_TC.MoveOperation.End)
        cur.insertImage(fmt)
        cur.insertText("\n")
        self.setTextCursor(cur)

    def extract_content(self):
        """解析输入框, 返回有序的部件列表: [{'type':'text','text':...}, {'type':'image','path':...}, ...]
        文字与图片按出现顺序穿插。"""
        parts = []
        doc = self.document()
        block = doc.begin()
        buf = []
        def flush_text():
            if buf:
                t = "".join(buf).strip("\n")
                if t.strip():
                    parts.append({"type": "text", "text": t})
                buf.clear()
        while block.isValid():
            it = block.begin()
            while not it.atEnd():
                frag = it.fragment()
                if frag.isValid():
                    cf = frag.charFormat()
                    if cf.isImageFormat():
                        flush_text()
                        name = cf.toImageFormat().name()
                        p = self._img_map.get(name)
                        if p:
                            parts.append({"type": "image", "path": p})
                    else:
                        buf.append(frag.text())
                it += 1
            buf.append("\n")
            block = block.next()
        flush_text()
        return parts

    def reset(self):
        self.clear()
        self._img_map.clear()
        self._img_counter = 0

    # ---- 双击发送框里的缩略图: 打开应用内图片编辑器(标注/裁剪/旋转) ----
    def mouseDoubleClickEvent(self, e):
        name = self._image_name_at(e.pos())
        if name and name in self._img_map:
            path = self._img_map[name]
            if path and os.path.exists(path):
                dlg = ImageEditorDialog(self.window(), path)
                if dlg.exec() and dlg.result_path:
                    self._replace_image(name, dlg.result_path)
                return
        super().mouseDoubleClickEvent(e)

    def _image_name_at(self, pos):
        from PyQt6.QtGui import QTextCursor as _TC
        cur = self.cursorForPosition(pos)
        p = cur.position()
        doc = self.document()
        for off in (0, -1):
            c = _TC(doc)
            c.setPosition(max(0, p + off))
            if not c.movePosition(_TC.MoveOperation.Right, _TC.MoveMode.KeepAnchor):
                continue
            fmt = c.charFormat()
            if fmt.isImageFormat():
                return fmt.toImageFormat().name()
        return None

    def _replace_image(self, name, newpath):
        """编辑完成后, 用新图片替换发送框里对应的缩略图与发送路径。"""
        from PyQt6.QtGui import QTextImageFormat, QImage as _QImage, QTextCursor as _TC
        img = _QImage(newpath)
        if img.isNull():
            return
        disp_w = min(160, img.width())
        ratio = disp_w / img.width() if img.width() else 1
        disp_h = int(img.height() * ratio)
        thumb = img.scaledToWidth(disp_w, Qt.TransformationMode.SmoothTransformation)
        self.document().addResource(3, QUrl(name), thumb)
        self._img_map[name] = newpath
        doc = self.document()
        block = doc.begin()
        while block.isValid():
            it = block.begin()
            while not it.atEnd():
                frag = it.fragment()
                if frag.isValid() and frag.charFormat().isImageFormat() \
                        and frag.charFormat().toImageFormat().name() == name:
                    cur = _TC(doc)
                    cur.setPosition(frag.position())
                    cur.setPosition(frag.position() + frag.length(), _TC.MoveMode.KeepAnchor)
                    fmt = QTextImageFormat()
                    fmt.setName(name)
                    fmt.setWidth(disp_w)
                    fmt.setHeight(disp_h)
                    cur.setCharFormat(fmt)
                    return
                it += 1
            block = block.next()

    # ---- 右键菜单: 剪贴板里有截图/文件时, 让“粘贴”可用 ----
    def contextMenuEvent(self, e):
        menu = self.createStandardContextMenu()
        cb = QApplication.clipboard()
        md = cb.mimeData() if cb is not None else None
        # QTextEdit.canPaste() 对纯图片剪贴板返回 False, 标准“粘贴”因而置灰;
        # 但我们的 insertFromMimeData 能处理图片/文件, 这里手动放开。
        if md is not None and (md.hasImage() or _extract_paths(md)):
            from PyQt6.QtGui import QKeySequence
            paste_seq = QKeySequence(QKeySequence.StandardKey.Paste)
            # 标准右键菜单里已有“Paste/粘贴”那一项, 这里把它找出来直接放开,
            # 不要再新增一项(否则会出现重复)。按快捷键与文案双重匹配以防本地化差异。
            paste_act = None
            for a in menu.actions():
                txt = a.text().replace("&", "")
                if a.shortcut() == paste_seq or "Paste" in txt or "粘贴" in txt:
                    paste_act = a
                    break
            if paste_act is not None:
                paste_act.setEnabled(True)  # 触发时会调用 paste() -> insertFromMimeData
        menu.exec(e.globalPos())

    # ---- 粘贴: 优先文件URL, 其次图片(避免复制文件时误粘上次截图) ----
    def insertFromMimeData(self, source):
        paths = _extract_paths(source)
        if paths:
            self.pathsAttached.emit(paths)
            return
        if source.hasImage():
            img = source.imageData()
            if not (isinstance(img, QImage) and not img.isNull()):
                # 某些来源 imageData() 取不到, 回退到剪贴板 image()
                cb = QApplication.clipboard()
                img = cb.image() if cb is not None else None
            if isinstance(img, QImage) and not img.isNull():
                p = _save_qimage(img)
                if p:
                    self.imageAttached.emit(p)
                return
        super().insertFromMimeData(source)

    # ---- 拖放 ----
    def dragEnterEvent(self, e):
        if e.mimeData().hasUrls() or e.mimeData().hasImage():
            e.acceptProposedAction()
        else:
            super().dragEnterEvent(e)

    def dragMoveEvent(self, e):
        if e.mimeData().hasUrls() or e.mimeData().hasImage():
            e.acceptProposedAction()
        else:
            super().dragMoveEvent(e)

    def dropEvent(self, e):
        md = e.mimeData()
        paths = _extract_paths(md)
        if paths:
            self.pathsAttached.emit(paths)
            e.acceptProposedAction()
            return
        if md.hasImage():
            img = md.imageData()
            if isinstance(img, QImage) and not img.isNull():
                p = _save_qimage(img)
                if p:
                    self.imageAttached.emit(p)
                e.acceptProposedAction()
                return
        super().dropEvent(e)


def _save_qimage(qimage):
    """把内存图片落地为 png, 返回路径。"""
    try:
        IMG_DIR.mkdir(parents=True, exist_ok=True)
        local = IMG_DIR / f"stage_{int(time.time()*1000)}_{os.getpid()}.png"
        qimage.save(str(local), "PNG")
        return str(local)
    except Exception:
        return None


