class PeerItem(QWidget):
    def __init__(self, name, ip, online, unread=0, queued=0):
        super().__init__()
        lay = QHBoxLayout(self)
        lay.setContentsMargins(14, 10, 14, 10)
        lay.setSpacing(12)
        dot = QLabel("●")
        dot.setObjectName("dotOn" if online else "dotOff")
        dot.setFixedWidth(12)
        lay.addWidget(dot, 0, Qt.AlignmentFlag.AlignVCenter)
        text = QVBoxLayout()
        text.setSpacing(1)
        nm = QLabel(name)
        nm.setObjectName("peerName" if online else "peerNameOff")
        sub_text = ip
        if not online:
            sub_text += "  · 离线"
        if queued > 0:
            sub_text += f"  · {queued} 条待发"
        ipl = QLabel(sub_text)
        ipl.setObjectName("peerIp" if online else "peerIpOff")
        text.addWidget(nm)
        text.addWidget(ipl)
        lay.addLayout(text)
        lay.addStretch()
        if queued > 0 and not online:
            ql = QLabel(f"⏳{queued}")
            ql.setObjectName("peerQueued")
            ql.setAlignment(Qt.AlignmentFlag.AlignCenter)
            lay.addWidget(ql, 0, Qt.AlignmentFlag.AlignVCenter)
        if unread > 0:
            badge = QLabel(str(unread) if unread < 100 else "99+")
            badge.setObjectName("unreadBadge")
            badge.setAlignment(Qt.AlignmentFlag.AlignCenter)
            badge.setFixedHeight(20)
            badge.setMinimumWidth(20)
            lay.addWidget(badge, 0, Qt.AlignmentFlag.AlignVCenter)


# ----------------------------- 主窗口 -----------------------------
class MainWindow(QMainWindow):
    def __init__(self):
        super().__init__()
        self.hostname = get_hostname()
        self.local_ip = get_local_ip()

        global RECV_ROOT
        APP_DATA.mkdir(parents=True, exist_ok=True)
        IMG_DIR.mkdir(parents=True, exist_ok=True)
        RECV_ROOT = load_recv_root()
        try:
            RECV_ROOT.mkdir(parents=True, exist_ok=True)
        except Exception:
            RECV_ROOT = DEFAULT_RECV_ROOT
            RECV_ROOT.mkdir(parents=True, exist_ok=True)

        self.known = self._load_devices()      # ip -> {"name":...}
        self.online = {}                       # ip -> {"name","port","online"}
        self.history = self._load_history()    # ip -> [...] 持久, 供聊天记录弹窗用
        self.session = {}                      # ip -> [...] 仅本次运行, 新开对话为空
        self.current_ip = None
        self.unread = {}                       # ip -> int 未读条数
        self.offline_queue = load_offline_queue()  # ip -> [{send_items, record_parts, ts}]
        self.staged_receives = {}              # ip -> [{parts, ts, name}] 待确认接收
        self._peer_list_state = {}             # 用于跳过无变化的重绘
        self._recv_meta = {}                   # recv_id -> {ip, label} 进行中的接收
        self._bubbles_by_id = {}               # msg_id -> Bubble 组件（用于取消时撤回气泡）
        self._send_ctrl: TransferControl | None = None   # 当前发送控制器
        self._send_units = {}    # unit_id -> {ctrl, ip, label, record} 在线按文件发送

        self.signals = Signals()
        self.signals.peers_changed.connect(self._on_peers_change)
        self.signals.log.connect(self._append_log)
        self.signals.chat_in.connect(self._on_chat_in)
        self.signals.sent.connect(self._after_sent)
        self.signals.staged.connect(self._stage_screenshot)
        self.signals.win_hide.connect(self._hide_for_shot)
        self.signals.win_show.connect(self._restore_after_shot)
        self.signals.recv_progress.connect(self._on_recv_progress)
        self.signals.send_unit_progress.connect(self._on_send_unit_progress)
        self.signals.send_unit_result.connect(self._on_send_unit_result)
        self.signals.recv_done.connect(self._on_recv_done)
        self.signals.recv_started.connect(self._on_recv_started)
        self.signals.recv_cancelled.connect(self._on_recv_cancelled)

        # macOS: 点击 Dock 图标时 QApplication 会发 ApplicationActive 状态,
        # 借此将被 hide() 隐藏的窗口还原到前台。
        if platform.system() == "Darwin":
            QApplication.instance().applicationStateChanged.connect(
                self._on_macos_app_activated)

        self.setWindowTitle("BitFerry 内网快传")
        self.setMinimumSize(*MIN_WIN_SIZE)
        restored = False
        if load_remember_window():
            geom = get_setting("window_geom", None)
            if geom:
                try:
                    restored = self.restoreGeometry(
                        QByteArray.fromBase64(geom.encode("ascii")))
                except Exception:
                    restored = False
        if not restored:
            self.resize(*load_window_size())
        self._build_ui()
        self.setStyleSheet(STYLE)
        self._force_quit = False
        self._tray_notified = False
        self._build_tray()
        self._shot_shortcut = None
        self._global_hotkey = None
        self._mac_hotkey = None
        self._install_shortcut(load_shortcut())

        self.discovery = Discovery(
            self.hostname, lambda p: self.signals.peers_changed.emit(p))
        self.discovery.start()
        # 向历史已知设备发单播，加速双向发现（解决 Windows 防火墙拦截广播的问题）
        self.discovery.ping_known(list(self.known.keys()))
        self.receiver = Receiver(
            on_file=self._on_file_received,
            on_chat=lambda n, ip, k, p: self.signals.chat_in.emit(n, ip, k, p),
            on_log=lambda m, k="info": self.signals.log.emit(m, k),
            on_progress=lambda rid, fn, d, t, sp: self.signals.recv_progress.emit(rid, fn, d, t, sp),
            get_recv_confirm=lambda: get_setting("recv_confirm", False),
            on_recv_started=lambda rid, sn, sip, meta: self.signals.recv_started.emit(rid, sn, sip, meta),
            on_recv_done=lambda rid: self.signals.recv_done.emit(rid),
            on_recv_cancelled=lambda rid: self.signals.recv_cancelled.emit(rid),
            on_peer_seen=lambda ip, name, uid, port: self.discovery.note_active_peer(
                ip, name, port, uid))
        self.receiver.start()

        self._rebuild_peer_list()

        # 启动后静默检查更新（延迟，避免拖慢启动）
        QTimer.singleShot(3000, lambda: self.action_check_update(manual=False))

    # ---------- 系统托盘 ----------
    def _make_icon(self):
        try:
            from PyQt6.QtCore import QByteArray
            data = base64.b64decode(ICON_B64)
            pm = QPixmap()
            pm.loadFromData(QByteArray(data))
            if not pm.isNull():
                return QIcon(pm)
        except Exception:
            pass
        pm = QPixmap(64, 64)
        pm.fill(QColor("transparent"))
        p = QPainter(pm)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        p.setBrush(_theme_accent())
        p.setPen(Qt.PenStyle.NoPen)
        p.drawRoundedRect(6, 6, 52, 52, 14, 14)
        p.setBrush(QColor("#0B0E14"))
        p.drawEllipse(24, 24, 16, 16)
        p.end()
        return QIcon(pm)

    def _build_tray(self):
        self.tray = None
        try:
            if not QSystemTrayIcon.isSystemTrayAvailable():
                return
            icon = self._make_icon()
            self.setWindowIcon(icon)
            self.tray = QSystemTrayIcon(icon, self)
            self.tray.setToolTip("BitFerry 内网快传")
            menu = QMenu()
            act_show = QAction("显示窗口", self)
            act_show.triggered.connect(self._restore_window)
            act_shot = QAction("截图", self)
            act_shot.triggered.connect(self.action_screenshot)
            act_recv = QAction("打开接收目录", self)
            act_recv.triggered.connect(self.action_open_recv)
            act_setting = QAction("设置", self)
            act_setting.triggered.connect(self._tray_open_settings)
            act_update = QAction("检查更新", self)
            act_update.triggered.connect(lambda: self.action_check_update(manual=True))
            act_quit = QAction("退出", self)
            act_quit.triggered.connect(self._tray_quit)
            menu.addAction(act_show)
            menu.addSeparator()
            menu.addAction(act_shot)
            menu.addAction(act_recv)
            menu.addAction(act_setting)
            menu.addAction(act_update)
            menu.addSeparator()
            menu.addAction(act_quit)
            self.tray.setContextMenu(menu)
            self.tray.activated.connect(self._on_tray_activated)
            self.tray.show()
        except Exception:
            self.tray = None

    def _on_tray_activated(self, reason):
        if reason in (QSystemTrayIcon.ActivationReason.Trigger,
                      QSystemTrayIcon.ActivationReason.DoubleClick):
            self._restore_window()

    # ---------- 在线更新 ----------
    def action_check_update(self, manual=False):
        """检查更新。manual=True 时会在"已最新/失败"也给出提示。"""
        self._update_manual = manual
        if getattr(self, "_update_checking", False):
            return
        self._update_checking = True
        sig = UpdateSignals()
        self._update_sig = sig            # 持有引用，避免被回收
        sig.available.connect(self._on_update_available)
        sig.uptodate.connect(self._on_update_uptodate)
        sig.failed.connect(self._on_update_failed)
        for s in (sig.available, sig.uptodate, sig.failed):
            s.connect(lambda *_: setattr(self, "_update_checking", False))
        check_for_update_async(sig)

    def _on_update_uptodate(self):
        if getattr(self, "_update_manual", False):
            QMessageBox.information(
                self, "检查更新", f"当前已是最新版本 {__version__}。")

    def _on_update_failed(self, msg):
        if getattr(self, "_update_manual", False):
            QMessageBox.warning(self, "检查更新", f"检查更新失败：\n{msg}")

    def _on_update_available(self, rel):
        # 记下待更新版本并在标题区亮出箭头徽标(不打扰)
        self._pending_update = rel
        if getattr(self, "btn_update_badge", None) is not None:
            self.btn_update_badge.setToolTip(
                f"发现新版本 {rel['version']}，点击查看")
            self.btn_update_badge.show()
        # 仅当用户手动点了"检查更新"时, 才立刻弹出详情
        if getattr(self, "_update_manual", False):
            self._show_update_dialog(rel)

    def _open_pending_update(self):
        rel = getattr(self, "_pending_update", None)
        if rel:
            self._show_update_dialog(rel)

    def _show_update_dialog(self, rel):
        box = QMessageBox(self)
        box.setWindowTitle("发现新版本")
        box.setText(f"发现新版本 {rel['version']}（当前 {__version__}）")
        box.setInformativeText(
            (_plain_notes(rel.get("notes")) or "无更新说明")[:1200])
        ok = box.addButton("立即更新", QMessageBox.ButtonRole.AcceptRole)
        box.addButton("以后再说", QMessageBox.ButtonRole.RejectRole)
        box.exec()
        if box.clickedButton() is ok:
            self._start_update_download(rel)

    def _start_update_download(self, rel):
        import webbrowser
        asset = rel.get("asset")
        # 没有当前平台的资产，或源码运行（无法自替换）：打开发布页让用户手动下载
        if not asset or not asset.get("url") or not getattr(sys, "frozen", False):
            webbrowser.open(rel.get("page") or GITHUB_RELEASES_PAGE)
            if not getattr(sys, "frozen", False):
                QMessageBox.information(
                    self, "更新",
                    "当前为源码运行，已打开发布页，请手动下载新版本。")
            return

        from PyQt6.QtWidgets import QProgressDialog, QProgressBar
        tmpdir = Path(tempfile.mkdtemp(prefix="bitferry_dl_"))
        dest = tmpdir / asset["name"]
        total = asset.get("size", 0)

        dlg = QProgressDialog("正在下载更新…", "取消", 0, max(total, 1), self)
        dlg.setWindowTitle("下载更新")
        dlg.setAutoClose(False)
        dlg.setAutoReset(False)
        dlg.setMinimumDuration(0)
        # 进度条自带的百分比文字在打包后会渲染成乱码, 隐藏它,
        # 改在标签里显示"已下载 X / Y MB (Z%)"。
        _bar = QProgressBar(dlg)
        _bar.setTextVisible(False)
        dlg.setBar(_bar)
        dlg.setValue(0)

        sig = _DLSignals()
        self._dl_sig = sig
        state = {"cancel": False}
        dlg.canceled.connect(lambda: state.update(cancel=True))

        _mb = 1024 * 1024

        def _progress(done, tot):
            if tot:
                dlg.setMaximum(tot)
                dlg.setValue(done)
                pct = int(done * 100 / tot)
                dlg.setLabelText(
                    f"正在下载更新… {done/_mb:.1f} / {tot/_mb:.1f} MB ({pct}%)")
            else:
                dlg.setRange(0, 0)
                dlg.setLabelText(f"正在下载更新… {done/_mb:.1f} MB")
        sig.progress.connect(_progress)

        def _done():
            dlg.close()
            try:
                if platform.system() == "Darwin":
                    apply_update_macos(dest)
                else:
                    apply_update_windows(dest)
            except Exception as e:
                QMessageBox.warning(self, "更新失败", f"安装更新时出错：\n{e}")
                return
            self._force_quit = True
            # 必须硬退出: 此处身处嵌套模态事件循环(dlg.exec / box.exec)内,
            # QApplication.quit() 往往无法真正结束进程 → 旧 exe 不退出、文件锁
            # 不释放, 更新脚本的等待循环就会一直卡住(残留命令行窗口、更新不生效)。
            # 先落盘再 os._exit 立即让出进程, 交给更新脚本完成替换并重启。
            try:
                self._save_history()
                self._save_devices()
            except Exception:
                pass
            os._exit(0)
        sig.finished.connect(_done)

        def _failed(msg):
            dlg.close()
            QMessageBox.warning(self, "下载失败", f"下载更新失败：\n{msg}")
        sig.failed.connect(_failed)

        def worker():
            try:
                ok = _download_with_progress(
                    asset["url"], dest, total,
                    progress_cb=lambda d, t: sig.progress.emit(d, t),
                    cancel_cb=lambda: state["cancel"])
                if ok:
                    sig.finished.emit()
            except Exception as e:
                sig.failed.emit(str(e))
        threading.Thread(target=worker, daemon=True).start()
        dlg.exec()

    def _tray_open_settings(self):
        # 从托盘打开设置: 先把窗口带到前台, 设置对话框才不会落在后面
        self._bring_to_front()
        self.action_settings()

    def _tray_quit(self):
        self._force_quit = True
        self.close()
        QApplication.quit()

    def _tray_icon_with_badge(self, count: int) -> QIcon:
        """在托盘图标右上角叠加未读数角标。"""
        if getattr(self, "_tray_base_pix", None) is None:
            self._tray_base_pix = self._make_icon().pixmap(QSize(64, 64))
        base = self._tray_base_pix
        if count <= 0:
            return QIcon(base)
        pm = QPixmap(base)
        # 注意: 高 DPI 下 pm.width() 是物理像素, 而 painter 工作在逻辑坐标,
        # 必须用逻辑宽度定位角标, 否则会画到图标外面。
        dpr = pm.devicePixelRatio() or 1.0
        logical_w = pm.width() / dpr
        p = QPainter(pm)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        d = 32
        x, y = int(logical_w - d - 1), 1
        p.setBrush(QColor("#FF3B30"))
        p.setPen(QPen(QColor("#FFFFFF"), 2))
        p.drawEllipse(x, y, d, d)
        txt = "99+" if count > 99 else str(count)
        p.setPen(QColor("#FFFFFF"))
        f = QFont()
        f.setBold(True)
        f.setPixelSize(20 if len(txt) < 3 else 13)
        p.setFont(f)
        p.drawText(QRect(x, y, d, d), Qt.AlignmentFlag.AlignCenter, txt)
        p.end()
        return QIcon(pm)

    def _restore_window(self):
        self._bring_to_front()

    def _on_macos_app_activated(self, state):
        """macOS: 用户点击 Dock 图标时 Qt 触发 ApplicationActive 状态，将隐藏的窗口恢复到前台。"""
        from PyQt6.QtCore import Qt
        if state == Qt.ApplicationState.ApplicationActive:
            if not self.isVisible() or self.isMinimized():
                self._bring_to_front()

    def _bring_to_front(self):
        """恢复窗口并尽量强制带到前台。

        Windows 在另一个程序处于前台时会拒绝 activateWindow()(前台锁),
        只闪烁任务栏而不真正置顶。这里用 AttachThreadInput 把本线程的输入
        队列临时挂到当前前台线程上, 从而绕过该限制可靠地置顶。
        """
        self.showNormal()
        self.raise_()
        self.activateWindow()
        if platform.system() == "Darwin":
            # activateWindow() 在 macOS 上对隐藏窗口常常无效,
            # 需通过 AppKit 告知系统让本应用抢占前台焦点。
            try:
                from AppKit import NSApplication  # type: ignore
                NSApplication.sharedApplication().activateIgnoringOtherApps_(True)
            except Exception:
                try:
                    subprocess.run(
                        ["osascript", "-e",
                         f"tell application \"System Events\" to set frontmost"
                         f" of first process whose unix id is {os.getpid()}"
                         f" to true"],
                        check=False, capture_output=True, timeout=2)
                except Exception:
                    pass
            return
        if platform.system() != "Windows":
            return
        try:
            import ctypes
            from ctypes import wintypes
            user32 = ctypes.windll.user32
            kernel32 = ctypes.windll.kernel32
            hwnd = int(self.winId())
            SW_RESTORE = 9
            SWP_NOMOVE = 0x0002
            SWP_NOSIZE = 0x0001
            SWP_NOACTIVATE = 0x0010
            HWND_TOPMOST = wintypes.HWND(-1)
            HWND_NOTOPMOST = wintypes.HWND(-2)
            user32.SetWindowPos.argtypes = [
                wintypes.HWND, wintypes.HWND, ctypes.c_int, ctypes.c_int,
                ctypes.c_int, ctypes.c_int, wintypes.UINT]
            # 1) 模拟一次 ALT 按键, 解除 Windows 的前台锁
            #    (否则后台进程调用 SetForegroundWindow 常被忽略, 只闪任务栏)。
            user32.keybd_event(0x12, 0, 0, 0)        # ALT down
            user32.keybd_event(0x12, 0, 0x0002, 0)   # ALT up (KEYEVENTF_KEYUP)
            # 2) 把本线程输入队列挂到当前前台线程, 进一步放开 SetForegroundWindow。
            fg = user32.GetForegroundWindow()
            fg_tid = user32.GetWindowThreadProcessId(fg, 0)
            cur_tid = kernel32.GetCurrentThreadId()
            attached = bool(fg_tid) and fg_tid != cur_tid and bool(
                user32.AttachThreadInput(fg_tid, cur_tid, True))
            user32.ShowWindow(hwnd, SW_RESTORE)
            # 3) 临时置顶把窗口提到 z 序最前再取消置顶, 保证视觉上"跳出来"。
            user32.SetWindowPos(wintypes.HWND(hwnd), HWND_TOPMOST, 0, 0, 0, 0,
                                SWP_NOMOVE | SWP_NOSIZE | SWP_NOACTIVATE)
            user32.SetWindowPos(wintypes.HWND(hwnd), HWND_NOTOPMOST, 0, 0, 0, 0,
                                SWP_NOMOVE | SWP_NOSIZE | SWP_NOACTIVATE)
            # 4) 抢键盘焦点。
            user32.SetForegroundWindow(hwnd)
            user32.BringWindowToTop(hwnd)
            user32.SetActiveWindow(hwnd)
            if attached:
                user32.AttachThreadInput(fg_tid, cur_tid, False)
        except Exception:
            pass

    # ---------- 持久化 ----------
    def _load_history(self):
        try:
            return json.loads(HISTORY_FILE.read_text(encoding="utf-8"))
        except Exception:
            return {}

    def _save_history(self):
        try:
            HISTORY_FILE.write_text(
                json.dumps(self.history, ensure_ascii=False), encoding="utf-8")
        except Exception:
            pass

    def _load_devices(self):
        try:
            return json.loads(DEVICES_FILE.read_text(encoding="utf-8"))
        except Exception:
            return {}

    def _save_devices(self):
        try:
            DEVICES_FILE.write_text(
                json.dumps(self.known, ensure_ascii=False), encoding="utf-8")
        except Exception:
            pass

    # ---------- UI ----------
    def _build_ui(self):
        root = QWidget()
        root.setObjectName("root")
        self.setCentralWidget(root)
        outer = QHBoxLayout(root)
        outer.setContentsMargins(0, 0, 0, 0)
        outer.setSpacing(0)

        # ===== 左侧设备栏 =====
        sidebar = QFrame()
        sidebar.setObjectName("sidebar")
        sidebar.setFixedWidth(280)
        sb = QVBoxLayout(sidebar)
        sb.setContentsMargins(20, 22, 20, 18)
        sb.setSpacing(12)

        brand_row = QHBoxLayout()
        brand_row.setContentsMargins(0, 0, 0, 0)
        brand_row.setSpacing(6)
        brand_row.addWidget(self._lbl("BitFerry", "brand"))
        # 有更新时才出现的箭头徽标, 点击查看更新内容
        self.btn_update_badge = QToolButton()
        self.btn_update_badge.setText("⬆ 更新")
        self.btn_update_badge.setObjectName("updateBadge")
